{
  "name": "LuxeStyle Studio - AI Fashion Sale Creator",
  "description": "An advanced tool for fashion brands to analyze style DNA, synchronize backgrounds, and create elegant sale promotional images with AI-driven aesthetics.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface ImageAnalysis {
  styleDna: {
    mood: string;
    vibe: string;
    colors: string[];
    fashionType: string;
  };
  backgroundDna: {
    lighting: string;
    texture: string;
    colorPalette: string[];
    depthOfField: string;
    consistencyNote: string;
  };
  recommendations: {
    font: string;
    bannerColor: string;
    layout: string;
  };
}

export interface SaleConfig {
  originalPrice: string;
  salePrice: string;
  discountPercentage: string;
  brandName: string;
  promotionText: string;
  theme: 'luxury' | 'minimal' | 'gentle' | 'modern';
  overlayPosition: 'bottom' | 'top' | 'center' | 'bottom-right';
}

export interface AppState {
  image: string | null;
  analysis: ImageAnalysis | null;
  isAnalyzing: boolean;
  config: SaleConfig;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";
import { ImageAnalysis } from "../types";

export const analyzeFashionImage = async (base64Image: string): Promise<ImageAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1],
            },
          },
          {
            text: "Analyze this fashion photo for a high-end sale campaign. Extract the 'Style DNA' (vibe, colors, luxury factors) and 'Background DNA' (lighting, texture, consistency elements). Suggest the best font and layout to keep a 'sang trọng, nhẹ nhàng' (elegant, gentle) look. Return valid JSON only.",
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          styleDna: {
            type: Type.OBJECT,
            properties: {
              mood: { type: Type.STRING },
              vibe: { type: Type.STRING },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } },
              fashionType: { type: Type.STRING },
            },
            required: ["mood", "vibe", "colors", "fashionType"]
          },
          backgroundDna: {
            type: Type.OBJECT,
            properties: {
              lighting: { type: Type.STRING },
              texture: { type: Type.STRING },
              colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
              depthOfField: { type: Type.STRING },
              consistencyNote: { type: Type.STRING },
            },
            required: ["lighting", "texture", "colorPalette", "depthOfField", "consistencyNote"]
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              font: { type: Type.STRING },
              bannerColor: { type: Type.STRING },
              layout: { type: Type.STRING },
            },
            required: ["font", "bannerColor", "layout"]
          },
        },
        required: ["styleDna", "backgroundDna", "recommendations"],
      },
    },
  });

  return JSON.parse(response.text);
};

import React from 'react';
import { SaleConfig } from '../types';

interface PreviewCanvasProps {
  image: string;
  config: SaleConfig;
}

const PreviewCanvas: React.FC<PreviewCanvasProps> = ({ image, config }) => {
  const getThemeStyles = () => {
    switch (config.theme) {
      case 'luxury':
        return {
          container: "bg-black/80 text-white border-gold-500",
          font: "font-serif",
          badge: "bg-amber-600 text-white px-2 py-0.5 text-xs uppercase tracking-widest"
        };
      case 'gentle':
        return {
          container: "bg-white/90 text-slate-800 border-rose-200",
          font: "font-sans font-light",
          badge: "bg-rose-100 text-rose-800 px-2 py-0.5 text-xs rounded-full"
        };
      case 'minimal':
        return {
          container: "bg-white text-black border-slate-900",
          font: "font-sans font-medium",
          badge: "bg-slate-900 text-white px-2 py-0.5 text-xs"
        };
      default:
        return {
          container: "bg-blue-600 text-white",
          font: "font-sans",
          badge: "bg-yellow-400 text-black px-2 py-0.5 text-xs"
        };
    }
  };

  const styles = getThemeStyles();

  const getPositionClass = () => {
    switch (config.overlayPosition) {
      case 'top': return 'top-8 left-0 right-0 items-center';
      case 'center': return 'top-1/2 left-0 right-0 -translate-y-1/2 items-center';
      case 'bottom-right': return 'bottom-8 right-8 items-end';
      default: return 'bottom-8 left-0 right-0 items-center';
    }
  };

  return (
    <div className="relative w-full max-w-2xl mx-auto rounded-xl overflow-hidden shadow-2xl bg-slate-200 aspect-[3/4]">
      <img src={image} alt="Fashion Preview" className="w-full h-full object-cover" />

      <div className={`absolute flex flex-col pointer-events-none w-full px-8 ${getPositionClass()}`}>
        <div className={`p-6 backdrop-blur-md rounded-lg border flex flex-col gap-2 transition-all duration-300 ${styles.container} ${config.overlayPosition === 'bottom-right' ? 'w-auto min-w-[200px]' : 'w-full max-w-md'}`}>
          <div className="flex justify-between items-center">
             <span className="text-xs tracking-tighter opacity-80 uppercase">{config.brandName || "LUXE STUDIO"}</span>
             {config.discountPercentage && (
                <span className={styles.badge}>{config.discountPercentage}% OFF</span>
             )}
          </div>

          <h2 className={`text-2xl ${styles.font} leading-tight`}>
            {config.promotionText || "SEASONAL CURATED COLLECTION"}
          </h2>

          <div className="flex items-baseline gap-3 mt-1">
            <span className={`text-3xl font-bold ${styles.font}`}>
               {config.salePrice ? `$${config.salePrice}` : "Contact for Price"}
            </span>
            {config.originalPrice && (
              <span className="text-lg line-through opacity-50 font-light">
                ${config.originalPrice}
              </span>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PreviewCanvas;

import React, { useState, useCallback } from 'react';
import { Camera, Upload, Trash2, Download, Settings2, Palette, ChevronRight, Sparkles, Loader2, DollarSign } from 'lucide-react';
import { AppState, SaleConfig } from './types';
import { analyzeFashionImage } from './services/geminiService';
import PreviewCanvas from './components/PreviewCanvas';
import AnalysisDisplay from './components/AnalysisDisplay';

const INITIAL_CONFIG: SaleConfig = {
  originalPrice: "1200",
  salePrice: "850",
  discountPercentage: "30",
  brandName: "L'ELEGANCE",
  promotionText: "THE CURATED WINTER ESSENTIALS",
  theme: 'luxury',
  overlayPosition: 'bottom'
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    image: null,
    analysis: null,
    isAnalyzing: false,
    config: INITIAL_CONFIG,
  });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = event.target?.result as string;
        setState(prev => ({ ...prev, image: base64, analysis: null, isAnalyzing: true }));

        try {
          const result = await analyzeFashionImage(base64);
          setState(prev => ({ ...prev, analysis: result, isAnalyzing: false }));
        } catch (error) {
          console.error("Analysis failed", error);
          setState(prev => ({ ...prev, isAnalyzing: false }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const updateConfig = (updates: Partial<SaleConfig>) => {
    setState(prev => ({ ...prev, config: { ...prev.config, ...updates } }));
  };

  return (
    <div className="min-h-screen bg-[#fafafa] text-slate-900 selection:bg-indigo-100">
      {/* Header */}
      <header className="border-b border-slate-200 bg-white/80 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <Sparkles size={20} fill="currentColor" />
            </div>
            <div>
              <h1 className="font-serif text-xl font-bold tracking-tight">LuxeStyle Studio</h1>
              <p className="text-[10px] uppercase tracking-[0.2em] text-slate-500 font-bold">AI Fashion Sale Engine</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <button 
              onClick={() => window.location.reload()}
              className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-600"
              title="New Session"
             >
               <Trash2 size={20} />
             </button>
             <button className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg font-medium transition-all shadow-sm">
                <Download size={18} />
                <span>Export Design</span>
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Panel: Preview & Analysis */}
        <div className="lg:col-span-7 space-y-8">
          {!state.image ? (
            <div className="aspect-[3/4] rounded-3xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center gap-6 bg-white shadow-sm hover:border-indigo-400 transition-colors group cursor-pointer relative">
              <input 
                type="file" 
                className="absolute inset-0 opacity-0 cursor-pointer" 
                onChange={handleImageUpload}
                accept="image/*"
              />
              <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-500 transition-all">
                <Upload size={32} />
              </div>
              <div className="text-center">
                <p className="font-medium text-slate-800">Upload high-res fashion photo</p>
                <p className="text-sm text-slate-400">Portrait 3:4 aspect ratio recommended</p>
              </div>
            </div>
          ) : (
            <div className="space-y-8">
              <PreviewCanvas image={state.image} config={state.config} />

              {state.isAnalyzing ? (
                <div className="p-12 text-center bg-white rounded-2xl border border-slate-200 flex flex-col items-center gap-4">
                  <Loader2 className="animate-spin text-indigo-600" size={32} />
                  <div className="space-y-1">
                    <p className="font-semibold">Gemini AI is analyzing DNA...</p>
                    <p className="text-sm text-slate-500">Mapping lighting, texture, and style consistencies</p>
                  </div>
                </div>
              ) : state.analysis && (
                <AnalysisDisplay analysis={state.analysis} />
              )}
            </div>
          )}
        </div>

        {/* Right Panel: Controls */}
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-6 sticky top-24">
            <div className="flex items-center gap-2 border-b border-slate-100 pb-4">
              <Settings2 size={20} className="text-slate-400" />
              <h2 className="font-bold uppercase tracking-wider text-sm">Sale Configuration</h2>
            </div>

            {/* Price Controls */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-xs font-bold uppercase text-slate-500 flex items-center gap-1">
                  <DollarSign size={12} /> Original Price
                </label>
                <input 
                  type="text" 
                  value={state.config.originalPrice}
                  onChange={(e) => updateConfig({ originalPrice: e.target.value })}
                  placeholder="e.g. 1000"
                  className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-xs font-bold uppercase text-indigo-600 flex items-center gap-1">
                  <Sparkles size={12} /> Sale Price
                </label>
                <input 
                  type="text" 
                  value={state.config.salePrice}
                  onChange={(e) => updateConfig({ salePrice: e.target.value })}
                  placeholder="e.g. 750"
                  className="w-full bg-indigo-50 border border-indigo-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-semibold"
                />
              </div>
              <div className="col-span-2 space-y-1.5">
                <label className="text-xs font-bold uppercase text-slate-500">Discount Label (%)</label>
                <input 
                  type="text" 
                  value={state.config.discountPercentage}
                  onChange={(e) => updateConfig({ discountPercentage: e.target.value })}
                  placeholder="e.g. 25"
                  className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none"
                />
              </div>
            </div>

            {/* Content Controls */}
            <div className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-xs font-bold uppercase text-slate-500">Brand Name / Headline</label>
                <input 
                  type="text" 
                  value={state.config.brandName}
                  onChange={(e) => updateConfig({ brandName: e.target.value })}
                  className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none"
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-xs font-bold uppercase text-slate-500">Promotion Message</label>
                <textarea 
                  rows={2}
                  value={state.config.promotionText}
                  onChange={(e) => updateConfig({ promotionText: e.target.value })}
                  className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none resize-none"
                />
              </div>
            </div>

            {/* Styling Presets */}
            <div className="space-y-3">
              <label className="text-xs font-bold uppercase text-slate-500 flex items-center gap-1">
                <Palette size={14} /> Style Preset
              </label>
              <div className="grid grid-cols-2 gap-2">
                {(['luxury', 'gentle', 'minimal', 'modern'] as const).map((t) => (
                  <button
                    key={t}
                    onClick={() => updateConfig({ theme: t })}
                    className={`px-4 py-2 rounded-lg text-xs font-medium capitalize border transition-all ${
                      state.config.theme === t 
                        ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' 
                        : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
                    }`}
                  >
                    {t}
                  </button>
                ))}
              </div>
            </div>

            {/* Layout Positioning */}
            <div className="space-y-3">
               <label className="text-xs font-bold uppercase text-slate-500">Overlay Position</label>
               <div className="flex gap-2">
                 {(['top', 'center', 'bottom', 'bottom-right'] as const).map((pos) => (
                    <button
                      key={pos}
                      onClick={() => updateConfig({ overlayPosition: pos })}
                      className={`flex-1 py-2 text-[10px] uppercase font-bold rounded border transition-all ${
                        state.config.overlayPosition === pos
                          ? 'bg-slate-800 text-white border-slate-800'
                          : 'bg-slate-50 text-slate-400 border-slate-200 hover:bg-slate-100'
                      }`}
                    >
                      {pos.replace('-', ' ')}
                    </button>
                 ))}
               </div>
            </div>

            <div className="pt-4 border-t border-slate-100">
               <p className="text-[10px] text-slate-400 text-center uppercase tracking-widest font-bold">
                 Syncing your background DNA...
               </p>
            </div>
          </section>
        </div>
      </main>

      <footer className="mt-12 py-12 border-t border-slate-200 bg-white">
        <div className="max-w-7xl mx-auto px-6 text-center">
          <p className="text-sm text-slate-500 font-serif italic">
            "Designed for luxury, engineered for sales."
          </p>
          <div className="mt-4 flex justify-center gap-8 text-xs font-bold uppercase tracking-widest text-slate-400">
             <span>Background Syncing</span>
             <span>Style DNA Analysis</span>
             <span>Smart Pricing</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

