  config: SaleConfig;
}

const PreviewCanvas: React.FC<PreviewCanvasProps> = ({ image, config }) => {
  const formatPrice = (price: string) => {
    if (!price) return "";
    const num = parseFloat(price.replace(/[^0-9]/g, ''));
    if (isNaN(num)) return price;
    return new Intl.NumberFormat('vi-VN').format(num);
  };

  const getThemeStyles = () => {
    switch (config.theme) {
      case 'luxury':
        return {
          container: "bg-black/85 text-white border-amber-500/30",
          font: "font-serif",
          badge: "bg-gradient-to-r from-amber-600 to-amber-400 text-white px-3 py-1 text-[10px] font-bold uppercase tracking-[0.2em] shadow-lg",
          priceColor: "text-amber-400",
          secondaryPrice: "text-white/40"
        };
      case 'gentle':
        return {
          container: "bg-white/95 text-slate-800 border-rose-100",
          font: "font-sans font-light tracking-wide",
          badge: "bg-rose-50 text-rose-600 border border-rose-100 px-3 py-0.5 text-[10px] font-semibold rounded-full",
          priceColor: "text-rose-800",
          secondaryPrice: "text-slate-400"
        };
      case 'minimal':
        return {
          container: "bg-white text-black border-slate-900 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)]",
          font: "font-sans font-bold tracking-tighter",
          badge: "bg-slate-900 text-white px-2 py-0.5 text-[10px]",
          priceColor: "text-black",
          secondaryPrice: "text-slate-400"
        };
      default:
        return {
          container: "bg-white/90 text-slate-900 border-slate-200",
          font: "font-sans font-medium",
          badge: "bg-indigo-600 text-white px-2 py-0.5 text-[10px]",
          priceColor: "text-indigo-600",
          secondaryPrice: "text-slate-400"
        };
    }
  };

  const styles = getThemeStyles();

  const getPositionClass = () => {
