import { GoogleGenAI, Type } from "@google/genai";
import { ImageAnalysis, SaleConfig } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeFashionImage = async (base64Image: string): Promise<ImageAnalysis> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1],
            },
          },
          {
            text: "Phân tích ảnh thời trang này. Trích xuất 'ADN Phong cách' và 'ADN Bối cảnh'. Đề xuất font chữ và bố cục để giữ vẻ 'sang trọng, nhẹ nhàng'. Phản hồi bằng tiếng Việt dưới dạng JSON.",
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          styleDna: {
            type: Type.OBJECT,
            properties: {
              mood: { type: Type.STRING },
              vibe: { type: Type.STRING },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } },
              fashionType: { type: Type.STRING },
            },
            required: ["mood", "vibe", "colors", "fashionType"]
          },
          backgroundDna: {
            type: Type.OBJECT,
            properties: {
              lighting: { type: Type.STRING },
              texture: { type: Type.STRING },
              colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
              depthOfField: { type: Type.STRING },
              consistencyNote: { type: Type.STRING },
            },
            required: ["lighting", "texture", "colorPalette", "depthOfField", "consistencyNote"]
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              font: { type: Type.STRING },
              bannerColor: { type: Type.STRING },
              layout: { type: Type.STRING },
            },
            required: ["font", "bannerColor", "layout"]
          },
        },
        required: ["styleDna", "backgroundDna", "recommendations"],
      },
    },
  });

  return JSON.parse(response.text);
};

export const generateAIImage = async (prompt: string, analysis: ImageAnalysis | null, theme: string): Promise<string> => {
  const dnaContext = analysis 
    ? `Follow this Style DNA: Mood is ${analysis.styleDna.mood}, Vibe is ${analysis.styleDna.vibe}. Background DNA: Lighting ${analysis.backgroundDna.lighting}, Texture ${analysis.backgroundDna.texture}.` 
    : "Luxury fashion photography, soft lighting, high-end editorial.";

  const fullPrompt = `Professional high-end fashion editorial photography. ${prompt}. ${dnaContext} Theme: ${theme}. 4k resolution, cinematic lighting, shallow depth of field, elegant and gentle aesthetic. No text in image.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: [{ parts: [{ text: fullPrompt }] }],
    config: {
      imageConfig: {
        aspectRatio: "3:4"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to generate image");
};

