            },
            required: ["mood", "vibe", "colors", "fashionType"]
          },
          backgroundDna: {
            type: Type.OBJECT,
            properties: {
              lighting: { type: Type.STRING },
              texture: { type: Type.STRING },
              colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
              depthOfField: { type: Type.STRING },
              consistencyNote: { type: Type.STRING },
            },
            required: ["lighting", "texture", "colorPalette", "depthOfField", "consistencyNote"]
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              font: { type: Type.STRING },
              bannerColor: { type: Type.STRING },
              layout: { type: Type.STRING },
            },
            required: ["font", "bannerColor", "layout"]
          },
        },
        required: ["styleDna", "backgroundDna", "recommendations"],
      },
    },
  });

  return JSON.parse(response.text);
};

export const generateAIImage = async (prompt: string, analysis: ImageAnalysis | null, theme: string): Promise<string> => {
  const dnaContext = analysis 
    ? `Follow this Style DNA: Mood is ${analysis.styleDna.mood}, Vibe is ${analysis.styleDna.vibe}. Background DNA: Lighting ${analysis.backgroundDna.lighting}, Texture ${analysis.backgroundDna.texture}.` 
    : "Luxury fashion photography, soft lighting, high-end editorial.";

  const fullPrompt = `Professional high-end fashion editorial photography for Tuấn Dz Studio. ${prompt}. ${dnaContext} Theme: ${theme}. 4k resolution, cinematic lighting, shallow depth of field, elegant and gentle aesthetic. Ensure consistent background and lighting. No text in image.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: [{ parts: [{ text: fullPrompt }] }],
    config: {
      imageConfig: {
        aspectRatio: "3:4"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to generate image");
};

