import { GoogleGenAI, Type } from "@google/genai";
import { ImageAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeFashionImage = async (base64Image: string): Promise<ImageAnalysis> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1],
            },
          },
          {
            text: "Phân tích ảnh thời trang này. Trích xuất 'ADN Phong cách' và 'ADN Bối cảnh'. Đề xuất font chữ sang trọng và bố cục tối giản. Phản hồi hoàn toàn bằng tiếng Việt dưới dạng JSON.",
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          styleDna: {
            type: Type.OBJECT,
            properties: {
              mood: { type: Type.STRING },
              vibe: { type: Type.STRING },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } },
              fashionType: { type: Type.STRING },
            },
            required: ["mood", "vibe", "colors", "fashionType"]
          },
          backgroundDna: {
            type: Type.OBJECT,
            properties: {
              lighting: { type: Type.STRING },
              texture: { type: Type.STRING },
              colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
              depthOfField: { type: Type.STRING },
              consistencyNote: { type: Type.STRING },
            },
            required: ["lighting", "texture", "colorPalette", "depthOfField", "consistencyNote"]
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              font: { type: Type.STRING },
              bannerColor: { type: Type.STRING },
              layout: { type: Type.STRING },
            },
            required: ["font", "bannerColor", "layout"]
          },
        },
        required: ["styleDna", "backgroundDna", "recommendations"],
      },
    },
  });

  return JSON.parse(response.text);
};

export const redesignBackground = async (originalImage: string, backgroundPrompt: string, theme: string): Promise<string> => {
  const fullPrompt = `Keep the model (the person, their pose, their face, and their clothing) from the provided image EXACTLY the same. Change ONLY the background and environment to: ${backgroundPrompt}. Style: High-end luxury fashion photoshoot, ${theme} aesthetic. Professional cinematic lighting, depth of field. Ensure a seamless integration between the model and the new environment. No text in image.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: originalImage.split(',')[1],
            },
          },
          { text: fullPrompt }
        ]
      }
    ],
    config: {
      imageConfig: {
        aspectRatio: "3:4"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to redesign background");
};

