                  value={backgroundPrompt}
                  onChange={(e) => setBackgroundPrompt(e.target.value)}
                  placeholder="VD: Phòng chờ khách sạn cổ điển tại Paris, ánh sáng hắt qua cửa sổ, nội thất gỗ nhung cao cấp..."
                  className="w-full bg-black/60 border border-white/10 rounded-3xl p-6 text-sm focus:border-amber-500/50 outline-none transition-all min-h-[150px] text-white/80 leading-relaxed group-hover:border-white/20"
                />
                <button 
                  onClick={handleBackgroundRedesign}
                  disabled={isGenerating || !backgroundPrompt || !originalImage}
                  className="absolute bottom-6 right-6 bg-amber-500 p-4 rounded-2xl text-black disabled:opacity-20 disabled:grayscale transition-all hover:scale-110 shadow-[0_10px_30px_rgba(245,158,11,0.4)] active:scale-95"
                  title="Thay đổi bối cảnh"
                >
                  <Sparkles size={24} />
                </button>
              </div>
              <p className="text-[9px] text-white/20 italic text-center">AI sẽ bảo tồn chi tiết người mẫu và trang phục, chỉ vẽ lại toàn bộ không gian xung quanh.</p>
            </div>
          </section>

          {/* Configuration */}
          <section className="bg-white/5 p-10 rounded-[40px] border border-white/10 space-y-10">
            <div className="flex items-center gap-4 border-b border-white/5 pb-6">
              <Settings2 size={22} className="text-white/20" />
              <h2 className="font-bold uppercase tracking-[0.3em] text-[11px]">Thông Số Quảng Cáo</h2>
            </div>

            <div className="grid grid-cols-2 gap-8">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-white/30 uppercase tracking-widest">Giá Niêm Yết</label>
                <div className="relative">
                  <input type="text" value={state.config.originalPrice} onChange={(e) => updateConfig({ originalPrice: e.target.value.replace(/\D/g,'') })} className="w-full bg-black/40 border border-white/10 rounded-2xl px-5 py-4 text-sm focus:border-white/40 outline-none font-fashion" />
