              <div className="space-y-3">
                <label className="text-[10px] font-black text-amber-500 uppercase tracking-widest">Giá Ưu Đãi</label>
                <div className="relative">
                  <input type="text" value={state.config.salePrice} onChange={(e) => updateConfig({ salePrice: e.target.value.replace(/\D/g,'') })} className="w-full bg-amber-500/5 border border-amber-500/20 rounded-2xl px-5 py-4 text-sm text-amber-500 font-bold focus:border-amber-500 outline-none font-fashion" />
                </div>
              </div>
            </div>

            <div className="space-y-8">
               <div className="space-y-3">
                  <label className="text-[10px] font-black text-white/30 uppercase tracking-widest">Thông Điệp Editorial</label>
                  <input type="text" value={state.config.promotionText} onChange={(e) => updateConfig({ promotionText: e.target.value })} className="w-full bg-black/40 border border-white/10 rounded-2xl px-5 py-4 text-sm focus:border-white/40 outline-none font-fashion italic" />
               </div>

               <div className="space-y-5">
                  <label className="text-[10px] font-black text-white/30 uppercase block text-center tracking-[0.3em]">Concept Thiết Kế</label>
                  <div className="grid grid-cols-2 gap-3">
                    {(['luxury', 'gentle', 'minimal', 'modern'] as const).map(t => (
                      <button key={t} onClick={() => updateConfig({ theme: t })} className={`py-4 rounded-2xl text-[10px] font-black uppercase transition-all border ${state.config.theme === t ? 'bg-white text-black border-white shadow-2xl scale-105' : 'bg-transparent text-white/30 border-white/10 hover:border-white/30'}`}>
