interface PreviewCanvasProps {
  image: string;
  config: SaleConfig;
}

const PreviewCanvas: React.FC<PreviewCanvasProps> = ({ image, config }) => {
  const formatPrice = (price: string) => {
    if (!price) return "";
    const num = parseFloat(price.replace(/[^0-9]/g, ''));
    if (isNaN(num)) return price;
    // Nếu giá trị nhỏ (như 99), giữ nguyên chữ K
    if (num < 1000) return `${num}K`;
    return new Intl.NumberFormat('vi-VN').format(num);
  };

  const getThemeStyles = () => {
    switch (config.theme) {
      case 'luxury':
        return {
          textMain: "text-[#8b2b2b]", // Đỏ rượu vang sang trọng
          textSub: "text-slate-500",
          fontTitle: "font-fashion font-bold italic",
          fontPrice: "font-sans font-black",
          bgOverlay: "bg-white/90"
        };
      case 'minimal':
        return {
          textMain: "text-black",
          textSub: "text-slate-400",
          fontTitle: "font-sans font-black uppercase tracking-tighter",
          fontPrice: "font-sans font-black",
          bgOverlay: "bg-white"
        };
      default:
        return {
          textMain: "text-slate-900",
          textSub: "text-slate-500",
          fontTitle: "font-fashion font-bold",
          fontPrice: "font-sans font-black",
          bgOverlay: "bg-white/80"
        };
    }
  };

  const styles = getThemeStyles();

  if (config.aspectRatio === '16:9') {
    return (
      <div className="relative w-full max-w-6xl mx-auto rounded-xl overflow-hidden shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)] bg-white aspect-[16/9] flex group border border-white/10">

        {/* Left 1:1 Panel */}
        <div className="w-1/2 h-full relative overflow-hidden border-r-2 border-white/20">
          <img src={image} className="w-full h-full object-cover grayscale-[20%] group-hover:scale-105 transition-transform duration-1000" alt="Model Left" />
          <div className="absolute inset-0 bg-white/10"></div>

          {/* Text Overlap Left */}
          <div className="absolute inset-y-0 right-0 w-full flex flex-col items-center justify-center translate-x-1/2 z-20 pointer-events-none">
             <div className="flex flex-col items-center text-center">
                <div className="mb-4">
                  <p className={`text-[14px] font-bold uppercase tracking-[0.4em] ${styles.textMain} opacity-80`}>{config.brandName}</p>
                </div>
                <h2 className={`${styles.fontTitle} text-7xl md:text-8xl leading-none tracking-widest ${styles.textMain} uppercase mb-2`}>
                   {config.promotionSubtitle || "LAST"}
                </h2>
                <div className="h-0.5 w-16 bg-current opacity-30 mb-8"></div>
                <p className={`text-[16px] font-black uppercase tracking-[0.2em] ${styles.textMain} mb-2`}>
                   {config.pricePrefix || "ĐỒNG GIÁ TỪ"}
                </p>
                <div className="flex items-start">
                   <span className={`${styles.fontPrice} text-[180px] leading-[0.8] tracking-tighter ${styles.textMain}`}>
                     {formatPrice(config.salePrice)}
                   </span>
                </div>
                <div className="mt-10 bg-white px-8 py-3 shadow-xl">
                   <p className={`text-[12px] font-black uppercase tracking-[0.3em] ${styles.textMain}`}>
                      {config.promotionText || "TOÀN BỘ SẢN PHẨM"}
                   </p>
                </div>
                <p className="mt-4 text-[9px] uppercase font-bold opacity-40 text-black">
                   {config.bottomNote || "(*) TRỪ SẢN PHẨM MỚI VỀ"}
                </p>
             </div>
          </div>
        </div>

        {/* Right 1:1 Panel */}
        <div className="w-1/2 h-full relative overflow-hidden">
          <img src={image} className="w-full h-full object-cover scale-x-[-1] opacity-90 group-hover:scale-x-[-1.05] transition-transform duration-1000" alt="Model Right" />
          <div className="absolute inset-0 bg-gradient-to-l from-black/20 to-transparent"></div>
        </div>

        {/* Split Line Indicator (Visual only) */}
        <div className="absolute top-0 bottom-0 left-1/2 -translate-x-1/2 w-0.5 bg-white/30 z-30 pointer-events-none border-l border-black/5"></div>
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-40 bg-black/60 text-white text-[8px] px-2 py-0.5 rounded-full uppercase font-black tracking-widest">Đường cắt FB</div>
      </div>
    );
  }

  // Fallback for other aspect ratios (keeping the existing high-end logic)
  const getAspectClass = () => {
    switch (config.aspectRatio) {
      case '1:1': return 'aspect-square';
      case '9:16': return 'aspect-[9/16]';
      case '4:5': return 'aspect-[4/5]';
      default: return 'aspect-[3/4]';
    }
  };

  return (
    <div className={`relative w-full max-w-2xl mx-auto rounded-3xl overflow-hidden shadow-2xl bg-slate-900 ${getAspectClass()} group`}>
      <img src={image} alt="Fashion" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000" />
      <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent"></div>

      <div className="absolute inset-0 p-12 flex flex-col justify-end pointer-events-none">
        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-8 duration-700">
          <div className="flex items-center gap-4">
             <span className="text-[12px] font-black uppercase tracking-[0.5em] text-white opacity-60 font-fashion">{config.brandName}</span>
             <span className="h-px w-8 bg-white/20"></span>
             <span className="bg-amber-500 text-black px-3 py-0.5 text-[9px] font-black uppercase tracking-widest">SALE {config.discountPercentage}%</span>
          </div>
          <h2 className="text-5xl font-fashion italic font-bold text-white leading-tight">
            {config.promotionSubtitle} {config.promotionText}
