              {formatPrice(config.salePrice)}<span className="text-2xl ml-1">đ</span>
            </span>
            <span className="text-xl line-through text-white/30 font-fashion italic">
              {formatPrice(config.originalPrice)}đ
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

