                    {formatPrice(config.salePrice)}
                  </span>
               </div>
            </div>

            {/* Bottom Tag */}
            <div className="mt-12 bg-white px-10 py-4 shadow-[0_20px_40px_rgba(0,0,0,0.1)] border border-black/5">
               <p className={`text-[13px] font-black uppercase tracking-[0.5em] ${styles.textMain}`}>
