export const redesignBackground = async (
  originalImage: string, 
  backgroundPrompt: string, 
  theme: string, 
  aspectRatio: string,
  analysis?: ImageAnalysis | null
): Promise<string> => {
  const dnaContext = analysis ? 
    `Use the existing background DNA: Lighting is ${analysis.backgroundDna.lighting}, Texture is ${analysis.backgroundDna.texture}, Color Palette includes ${analysis.backgroundDna.colorPalette.join(', ')}.` : "";

  const outpaintInstructions = aspectRatio === '16:9' 
    ? "AI OUTPAINTING TASK: Extend the canvas to 16:9 widescreen. KEEP the original subject and existing background in the center UNCHANGED. Seamlessly DRAW and EXPAND the environment to the left and right sides to fill the wide frame. The transition must be invisible."
    : "KEEP the original subject and pose perfectly. Redesign the environment around them.";

  const fullPrompt = `${outpaintInstructions} ${dnaContext} New background description: ${backgroundPrompt}. Style: Professional high-end luxury fashion photography, ${theme} mood. Cinematic lighting, smooth depth of field. NO text, NO logos in the background.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: originalImage.split(',')[1],
            },
          },
          { text: fullPrompt }
        ]
      }
    ],
    config: {
      imageConfig: {
        aspectRatio: aspectRatio as any
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to generate expanded image");
};

