import { GoogleGenAI, Type } from "@google/genai";
import { ImageAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeFashionImage = async (base64Image: string): Promise<ImageAnalysis> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1],
            },
          },
          {
            text: "Phân tích ảnh thời trang này chuyên sâu. 1. Trích xuất 'ADN Phong cách': tâm trạng, loại trang phục, đặc điểm mẫu mặc. 2. Trích xuất 'ADN Bối cảnh' hiện tại. 3. Đề xuất 3 'Chủ đề bối cảnh' (suggestedThemes) để làm nổi bật trang phục (ví dụ: bối cảnh tối giản cho đồ cầu kỳ, bối cảnh cổ điển cho đồ sang trọng). Phản hồi hoàn toàn bằng tiếng Việt dưới dạng JSON.",
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          styleDna: {
            type: Type.OBJECT,
            properties: {
              mood: { type: Type.STRING },
              vibe: { type: Type.STRING },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } },
              fashionType: { type: Type.STRING },
              modelCharacter: { type: Type.STRING },
            },
            required: ["mood", "vibe", "colors", "fashionType", "modelCharacter"]
          },
          backgroundDna: {
            type: Type.OBJECT,
            properties: {
              lighting: { type: Type.STRING },
              texture: { type: Type.STRING },
              colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
              depthOfField: { type: Type.STRING },
              consistencyNote: { type: Type.STRING },
            },
            required: ["lighting", "texture", "colorPalette", "depthOfField", "consistencyNote"]
          },
          suggestedThemes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                prompt: { type: Type.STRING },
                description: { type: Type.STRING },
              },
              required: ["name", "prompt", "description"]
            }
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              font: { type: Type.STRING },
              bannerColor: { type: Type.STRING },
              layout: { type: Type.STRING },
            },
            required: ["font", "bannerColor", "layout"]
          },
        },
        required: ["styleDna", "backgroundDna", "suggestedThemes", "recommendations"],
      },
    },
  });

  return JSON.parse(response.text);
};

export const redesignBackground = async (
  originalImage: string, 
  backgroundPrompt: string, 
  theme: string, 
  aspectRatio: string,
  analysis?: ImageAnalysis | null
): Promise<string> => {
  const dnaContext = analysis ? 
    `Model DNA: ${analysis.styleDna.modelCharacter}. Fashion style: ${analysis.styleDna.fashionType}. Ensure the background enhances these features.` : "";

  const outpaintInstructions = aspectRatio === '16:9' 
    ? "TASK: AI OUTPAINTING. Keep the model/garment perfectly centered and unchanged. Expand the environment horizontally to 16:9. The expansion must be seamless and contextually consistent with the analyzed style."
    : "Keep the subject unchanged and recreate the surrounding environment to be high-end.";

  const fullPrompt = `${outpaintInstructions} ${dnaContext} New background requirement: ${backgroundPrompt}. Aesthetic: ${theme}. Lighting should be cinematic and flattering for fashion. High-end photography quality. NO TEXT.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: originalImage.split(',')[1],
            },
          },
          { text: fullPrompt }
        ]
      }
    ],
    config: {
      imageConfig: {
        aspectRatio: aspectRatio as any
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Generation failed");
};

