          </div>
        </div>
        <div className="absolute top-0 bottom-0 left-1/2 -translate-x-1/2 w-px bg-white/30 z-30 pointer-events-none"></div>
      </div>
    );
  }

  // Story 9:16
  if (config.aspectRatio === '9:16') {
    return (
      <div className="relative w-full max-w-sm mx-auto rounded-3xl overflow-hidden shadow-2xl bg-slate-900 aspect-[9/16] group">
        <img src={image} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105" alt="Story" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent"></div>
        <div className="absolute top-10 left-0 right-0 flex justify-center opacity-40">
           {config.logo ? <img src={config.logo} className="h-8 object-contain invert" alt="L" /> : <span className="text-white text-[10px] tracking-[0.5em] font-black uppercase">{config.brandName}</span>}
