import React, { useState, useEffect } from 'react';
import { Upload, Trash2, Download, Settings2, Palette, Sparkles, Loader2, Wand2, RefreshCcw, Camera, Layout, Store, Scissors, Type as FontIcon, Maximize, Image as ImageIcon, Hash, Tag, CircleDollarSign } from 'lucide-react';
import { AppState, SaleConfig } from './types';
import { analyzeFashionImage, redesignBackground } from './services/geminiService';
import PreviewCanvas from './components/PreviewCanvas';
import AnalysisDisplay from './components/AnalysisDisplay';

const INITIAL_CONFIG: SaleConfig = {
  originalPrice: "1250000",
  salePrice: "199",
  discountPercentage: "80",
  brandName: "TUẤN STUDIO",
  productCode: "FSH-2025",
  logo: null,
  promotionText: "TRÊN TOÀN HỆ THỐNG",
  promotionSubtitle: "SPECIAL",
  pricePrefix: "ĐỒNG GIÁ TỪ",
  bottomNote: "(*) SỐ LƯỢNG CÓ HẠN",
  theme: 'luxury',
  overlayPosition: 'bottom',
  aspectRatio: '1:1'
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    image: null,
    analysis: null,
    isAnalyzing: false,
    config: INITIAL_CONFIG,
  });
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [backgroundPrompt, setBackgroundPrompt] = useState("");

  const updateConfig = (updates: Partial<SaleConfig>) => {
    setState(prev => ({ ...prev, config: { ...prev.config, ...updates } }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = event.target?.result as string;
        setOriginalImage(base64);
        setState(prev => ({ ...prev, image: base64, analysis: null, isAnalyzing: true }));
        try {
          const result = await analyzeFashionImage(base64);
          setState(prev => ({ ...prev, analysis: result, isAnalyzing: false }));
        } catch (error) {
          setState(prev => ({ ...prev, isAnalyzing: false }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        updateConfig({ logo: event.target?.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const applyTheme = (prompt: string) => {
    setBackgroundPrompt(prompt);
  };

  const handleBackgroundRedesign = async () => {
    if (!originalImage) return;
    setIsGenerating(true);
    try {
      const finalPrompt = backgroundPrompt || (state.analysis ? `Luxury fashion studio, minimal aesthetic, lighting consistent with ${state.analysis.backgroundDna.lighting}` : "Luxury fashion studio background");
      const redesignedUrl = await redesignBackground(
        originalImage, 
        finalPrompt, 
        state.config.theme, 
        state.config.aspectRatio,
        state.analysis
      );
      setState(prev => ({ ...prev, image: redesignedUrl }));
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0b0d] text-white/90">
      <header className="border-b border-white/5 bg-black/40 backdrop-blur-3xl sticky top-0 z-50">
        <div className="max-w-[1600px] mx-auto px-10 h-24 flex items-center justify-between">
          <div className="flex items-center gap-5">
            <div className="w-14 h-14 bg-gradient-to-tr from-amber-500 to-yellow-200 rounded-full flex items-center justify-center shadow-[0_0_30px_rgba(251,191,36,0.3)]">
              <Sparkles size={28} className="text-black" />
            </div>
            <div>
              <h1 className="font-fashion text-3xl font-bold tracking-tight">TUẤN DZ <span className="text-[10px] font-sans bg-white text-black px-2 py-0.5 ml-2 rounded font-black">AI STUDIO</span></h1>
              <p className="text-[10px] uppercase tracking-[0.5em] text-white/30 font-bold">Fashion Ad Design specialist</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <button onClick={() => window.location.reload()} className="p-4 text-white/20 hover:text-white transition-all">
               <RefreshCcw size={20} />
             </button>
             <button className="bg-white text-black px-8 py-4 rounded-full font-black text-[11px] tracking-[0.2em] hover:bg-red-600 hover:text-white transition-all shadow-xl active:scale-95">
                XUẤT FILE 4K (ULTRA HD)
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-[1600px] mx-auto p-10 grid grid-cols-1 lg:grid-cols-12 gap-16">
        {/* Left Column: Preview & Analysis */}
        <div className="lg:col-span-7 space-y-12">
          {!state.image ? (
            <div className="aspect-square max-w-2xl mx-auto rounded-[50px] border-2 border-dashed border-white/10 bg-white/5 flex flex-col items-center justify-center gap-10 group cursor-pointer relative overflow-hidden transition-all hover:bg-white/[0.07] hover:border-red-500/50">
               <input type="file" className="absolute inset-0 opacity-0 cursor-pointer z-10" onChange={handleImageUpload} />
               <div className="w-28 h-28 bg-white/5 rounded-full flex items-center justify-center text-white/10 group-hover:scale-110 group-hover:text-red-500 transition-all border border-white/5 shadow-inner">
                 <Camera size={48} />
               </div>
               <div className="text-center z-10 space-y-3 px-10">
                 <p className="text-2xl font-fashion italic">Tải Ảnh Mẫu Lên</p>
                 <p className="text-[10px] text-white/20 uppercase tracking-[0.3em] font-bold">AI sẽ phân tích trang phục & đề xuất bối cảnh tôn dáng nhất</p>
               </div>
            </div>
          ) : (
            <div className="space-y-12 animate-in fade-in zoom-in-95 duration-1000">
              <div className="relative group">
                {isGenerating && (
                  <div className="absolute inset-0 z-20 bg-black/90 backdrop-blur-2xl flex flex-col items-center justify-center rounded-[32px]">
