import React, { useState, useRef, useEffect } from 'react';
import { SaleConfig } from '../types';

interface PreviewCanvasProps {
  image: string;
  config: SaleConfig;
  onUpdateOverlay?: (updates: Partial<SaleConfig>) => void;
}

const PreviewCanvas: React.FC<PreviewCanvasProps> = ({ image, config, onUpdateOverlay }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const formatPrice = (price: string) => {
    if (!price) return "";
    const num = parseFloat(price.replace(/[^0-9]/g, ''));
    if (isNaN(num)) return price;
    if (num < 1000) return `${num}K`;
    return new Intl.NumberFormat('vi-VN').format(num);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!containerRef.current || !onUpdateOverlay) return;

    setIsDragging(true);
    const rect = containerRef.current.getBoundingClientRect();

    // Tính toán độ lệch giữa chuột và tâm hiện tại của overlay
    const overlayXpx = (config.overlayX / 100) * rect.width;
    const overlayYpx = (config.overlayY / 100) * rect.height;

    setDragOffset({
      x: e.clientX - rect.left - overlayXpx,
      y: e.clientY - rect.top - overlayYpx
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging || !containerRef.current || !onUpdateOverlay) return;

      const rect = containerRef.current.getBoundingClientRect();
      const newXpx = e.clientX - rect.left - dragOffset.x;
      const newYpx = e.clientY - rect.top - dragOffset.y;

      // Chuyển đổi px sang % để lưu trữ (đảm bảo phản hồi với resize)
      const newXpct = Math.min(Math.max((newXpx / rect.width) * 100, 5), 95);
      const newYpct = Math.min(Math.max((newYpx / rect.height) * 100, 5), 95);

      onUpdateOverlay({
        overlayX: newXpct,
        overlayY: newYpct
      });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, dragOffset, onUpdateOverlay]);

  const getThemeStyles = () => {
    switch (config.theme) {
      case 'luxury':
        return {
          textMain: "text-amber-900",
          fontMain: "font-fashion font-bold italic",
          fontPrice: "font-sans font-black",
          accent: "text-red-600",
        };
      case 'gentle':
        return {
          textMain: "text-rose-900",
          fontMain: "font-fashion",
          fontPrice: "font-sans font-black",
          accent: "text-red-600",
        };
      case 'minimal':
        return {
          textMain: "text-black",
          fontMain: "font-sans font-black uppercase tracking-tighter",
          fontPrice: "font-sans font-black",
          accent: "text-red-600",
        };
      default:
        return {
          textMain: "text-slate-900",
          fontMain: "font-sans font-bold",
          fontPrice: "font-sans font-black",
          accent: "text-red-600",
        };
    }
  };

  const styles = getThemeStyles();

  // Overlay Wrapper Style (Draggable container)
  const overlayWrapperStyle: React.CSSProperties = {
    position: 'absolute',
    left: `${config.overlayX}%`,
    top: `${config.overlayY}%`,
    transform: `translate(-50%, -50%) scale(${config.overlayScale})`,
    cursor: isDragging ? 'grabbing' : 'grab',
    userSelect: 'none',
    width: '100%',
    pointerEvents: 'auto'
  };

  // Logo Style with individual scale
  const logoStyle: React.CSSProperties = {
    transform: `scale(${config.logoScale})`,
    transformOrigin: 'top left'
  };

  // Layout 16:9 Split
  if (config.aspectRatio === '16:9') {
    return (
      <div 
        ref={containerRef}
        className="relative w-full max-w-6xl mx-auto rounded-2xl overflow-hidden shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)] bg-white aspect-[16/9] flex group border border-white/10"
      >
        <div className="w-1/2 h-full relative overflow-hidden border-r border-white/20">
          <img src={image} className="w-[200%] max-w-none h-full object-cover" style={{ objectPosition: 'left center' }} alt="L" />
        </div>
        <div className="w-1/2 h-full relative overflow-hidden">
          <img src={image} className="w-[200%] max-w-none h-full object-cover -translate-x-1/2" style={{ objectPosition: 'right center' }} alt="R" />
        </div>

        {/* Logo Overlay */}
        {config.logo && (
          <div className="absolute top-10 left-10 z-30 opacity-60 pointer-events-none" style={logoStyle}>
            <img src={config.logo} className="h-10 object-contain grayscale invert" alt="Logo" />
          </div>
        )}

        <div 
          style={overlayWrapperStyle}
          onMouseDown={handleMouseDown}
          className="z-20 flex flex-col items-center text-center px-4"
        >
          <div className="mb-4">
            <span className={`text-[12px] font-black uppercase tracking-[0.6em] ${styles.textMain} opacity-60`}>
              {config.brandName}
            </span>
          </div>
          <h2 className={`${styles.fontMain} text-7xl md:text-9xl leading-[0.7] tracking-tighter ${styles.textMain} uppercase mb-4`}>
            {config.promotionSubtitle}
          </h2>
          <div className="space-y-2">
            <p className={`text-[14px] font-black uppercase tracking-[0.4em] text-red-600 mb-2`}>
              {config.pricePrefix}
            </p>
            <span className={`${styles.fontPrice} text-[150px] md:text-[220px] leading-[0.7] tracking-tighter text-red-600`}>
              {formatPrice(config.salePrice)}
            </span>
          </div>
          <div className="mt-14 bg-white/90 backdrop-blur-md px-10 py-4 shadow-xl border border-black/5">
             <p className={`text-[13px] font-black uppercase tracking-[0.4em] text-red-600`}>
                {config.promotionText}
             </p>
          </div>
          {config.productCode && (
            <div className="mt-8">
              <span className="text-[10px] font-mono tracking-[0.5em] text-black opacity-30 uppercase">CODE: {config.productCode}</span>
            </div>
          )}
        </div>
        <div className="absolute top-0 bottom-0 left-1/2 -translate-x-1/2 w-px bg-white/30 z-30 pointer-events-none"></div>
      </div>
    );
  }

  // Story 9:16
  if (config.aspectRatio === '9:16') {
    return (
      <div 
        ref={containerRef}
        className="relative w-full max-w-sm mx-auto rounded-3xl overflow-hidden shadow-2xl bg-slate-900 aspect-[9/16] group"
      >
        <img src={image} className="w-full h-full object-cover" alt="Story" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent pointer-events-none"></div>

        {config.logo && (
          <div className="absolute top-10 left-0 right-0 flex justify-center opacity-40 pointer-events-none z-10" style={{ transform: `scale(${config.logoScale})`, transformOrigin: 'center' }}>
            <img src={config.logo} className="h-8 object-contain invert" alt="L" />
          </div>
        )}

        <div 
          style={overlayWrapperStyle}
          onMouseDown={handleMouseDown}
          className="px-6 flex flex-col items-center text-center z-20"
        >
           <h2 className="text-6xl text-white font-fashion italic font-bold mb-2">{config.promotionSubtitle}</h2>
           <p className="text-red-500 font-black text-6xl mb-4">{formatPrice(config.salePrice)}đ</p>
           <div className="h-px w-20 bg-white/20 mb-6"></div>
           <p className="text-white/80 uppercase tracking-widest text-[11px] font-bold mb-4">{config.promotionText}</p>
           {config.productCode && (
              <span className="text-[9px] font-mono text-white/20 tracking-widest uppercase">MÃ: {config.productCode}</span>
           )}
        </div>
      </div>
    );
  }

  const getAspectClass = () => {
    switch (config.aspectRatio) {
      case '1:1': return 'aspect-square';
      case '4:5': return 'aspect-[4/5]';
      default: return 'aspect-[3/4]';
    }
  };

  return (
    <div 
      ref={containerRef}
      className={`relative w-full max-w-2xl mx-auto rounded-3xl overflow-hidden shadow-2xl bg-slate-900 ${getAspectClass()} group border border-white/5`}
    >
      <img src={image} alt="Fashion" className="w-full h-full object-cover" />
      <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent pointer-events-none"></div>

      {/* Branding fixo */}
      <div className="absolute top-8 left-8 flex items-center gap-4 opacity-50 pointer-events-none z-10" style={logoStyle}>
        {config.logo && <img src={config.logo} className="h-8 object-contain invert" alt="L" />}
        <span className="text-[10px] font-black tracking-widest text-white uppercase">{config.brandName}</span>
      </div>

      <div 
        style={overlayWrapperStyle}
        onMouseDown={handleMouseDown}
        className="px-12 flex flex-col z-20"
      >
        <div className="flex flex-col gap-4">
            <div className="flex items-center gap-4">
              <span className={`text-[12px] font-bold uppercase tracking-[0.6em] text-white opacity-80 font-fashion italic`}>
                {config.promotionSubtitle}
              </span>
              {config.discountPercentage && config.discountPercentage !== "0" && (
                <span className="bg-red-600 text-white px-3 py-0.5 text-[9px] font-black uppercase tracking-widest">-{config.discountPercentage}%</span>
              )}
            </div>
            <h2 className="text-6xl leading-[0.9] text-white font-fashion italic font-bold">
              SALE <span className="block text-4xl not-italic opacity-60 uppercase">{config.promotionText}</span>
            </h2>
            <div className="pt-4 flex items-baseline justify-between">
                <div className="flex items-baseline gap-2">
                  <span className="text-6xl font-black font-sans tracking-tighter text-red-600">
                    {formatPrice(config.salePrice)}<span className="text-2xl ml-1 font-bold">đ</span>
                  </span>
                  <span className="text-white/40 line-through text-lg font-bold">{formatPrice(config.originalPrice)}đ</span>
