export interface SaleConfig {
  originalPrice: string;
  salePrice: string;
  discountPercentage: string;
  brandName: string;
  productCode: string;
  logo: string | null;
  promotionText: string;
  promotionSubtitle: string; 
  pricePrefix: string;      
  bottomNote: string;       
  theme: 'luxury' | 'minimal' | 'gentle' | 'modern';
  overlayPosition: 'bottom' | 'top' | 'center' | 'bottom-right';
  aspectRatio: '3:4' | '1:1' | '9:16' | '4:5' | '16:9';
