              <div className="flex items-center gap-4">
                <Layout size={20} className="text-white/40" />
                <h2 className="font-bold uppercase tracking-[0.3em] text-[11px]">Cấu hình & Kích thước</h2>
              </div>
            </div>
            <div className="grid grid-cols-5 gap-2">
              {(['1:1', '3:4', '4:5', '9:16', '16:9'] as const).map(ratio => (
                <button key={ratio} onClick={() => updateConfig({ aspectRatio: ratio })} className={`py-4 rounded-xl text-[9px] font-black transition-all border ${state.config.aspectRatio === ratio ? 'bg-red-600 text-white border-red-600' : 'bg-transparent text-white/20 border-white/5'}`}>
                  {ratio}
                </button>
              ))}
            </div>

            <div className="space-y-4 pt-4 border-t border-white/5">
              <div className="flex justify-between items-center">
                <label className="text-[10px] font-black text-white/30 uppercase tracking-widest flex items-center gap-2">
                  <Maximize size={14} /> Phóng to Nội dung Sale
