                 </div>
                 <div className="space-y-1">
                    <div className="flex justify-between">
                      <span className="text-[8px] text-white/20 uppercase font-black tracking-tighter">Size Logo</span>
                      <span className="text-[8px] text-red-500 font-mono">{Math.round(state.config.logoScale * 100)}%</span>
                    </div>
                    <input 
                      type="range" 
                      min="0.3" 
                      max="2.5" 
                      step="0.1" 
                      value={state.config.logoScale} 
                      onChange={(e) => updateConfig({ logoScale: parseFloat(e.target.value) })}
                      className="w-full accent-red-600 h-1 rounded-full appearance-none cursor-pointer"
                    />
                 </div>
                 <button onClick={() => updateConfig({ logoX: 5, logoY: 5 })} className="text-[8px] font-black text-white/20 hover:text-white uppercase tracking-tighter">Reset Logo</button>
              </div>

              {/* Brand Name Control */}
              <div className="space-y-4">
                 <label className="text-[10px] font-black text-white/30 uppercase tracking-widest">Tên Shop</label>
                 <input 
                   type="text" 
                   value={state.config.brandName} 
                   onChange={(e) => updateConfig({ brandName: e.target.value })} 
                   className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-4 h-20 text-xs font-fashion font-bold uppercase tracking-widest outline-none focus:border-red-500" 
                 />
                 <div className="space-y-1">
                    <div className="flex justify-between">
                      <span className="text-[8px] text-white/20 uppercase font-black tracking-tighter">Size Chữ</span>
                      <span className="text-[8px] text-red-500 font-mono">{Math.round(state.config.brandNameScale * 100)}%</span>
                    </div>
                    <input 
                      type="range" 
                      min="0.5" 
                      max="2.5" 
                      step="0.1" 
                      value={state.config.brandNameScale} 
                      onChange={(e) => updateConfig({ brandNameScale: parseFloat(e.target.value) })}
                      className="w-full accent-red-600 h-1 rounded-full appearance-none cursor-pointer"
                    />
                 </div>
                 <button onClick={() => updateConfig({ brandNameX: 5, brandNameY: 12 })} className="text-[8px] font-black text-white/20 hover:text-white uppercase tracking-tighter">Reset Tên</button>
              </div>
            </div>

            <div className="space-y-3 pt-4 border-t border-white/5">
                 <label className="text-[10px] font-black text-white/30 uppercase tracking-widest">Mã Sản Phẩm</label>
                 <div className="relative">
                   <Hash size={14} className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20" />
                   <input 
