import React, { useState, useRef, useEffect } from 'react';
import { SaleConfig } from '../types';

interface PreviewCanvasProps {
  image: string;
  config: SaleConfig;
  onUpdateOverlay?: (updates: Partial<SaleConfig>) => void;
}

const PreviewCanvas: React.FC<PreviewCanvasProps> = ({ image, config, onUpdateOverlay }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragTarget, setDragTarget] = useState<'overlay' | 'logo' | 'brand' | null>(null);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const formatPrice = (price: string) => {
    if (!price) return "";
    const num = parseFloat(price.replace(/[^0-9]/g, ''));
    if (isNaN(num)) return price;
    if (num < 1000) return `${num}K`;
    return new Intl.NumberFormat('vi-VN').format(num);
  };

  const handleMouseDown = (e: React.MouseEvent, target: 'overlay' | 'logo' | 'brand') => {
    if (!containerRef.current || !onUpdateOverlay) return;

    e.stopPropagation();
    setDragTarget(target);
    const rect = containerRef.current.getBoundingClientRect();

    let currentX = 0, currentY = 0;
    if (target === 'overlay') { currentX = config.overlayX; currentY = config.overlayY; }
    else if (target === 'logo') { currentX = config.logoX; currentY = config.logoY; }
    else if (target === 'brand') { currentX = config.brandNameX; currentY = config.brandNameY; }

    const targetXpx = (currentX / 100) * rect.width;
    const targetYpx = (currentY / 100) * rect.height;

    setDragOffset({
      x: e.clientX - rect.left - targetXpx,
      y: e.clientY - rect.top - targetYpx
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragTarget || !containerRef.current || !onUpdateOverlay) return;

      const rect = containerRef.current.getBoundingClientRect();
      const newXpx = e.clientX - rect.left - dragOffset.x;
      const newYpx = e.clientY - rect.top - dragOffset.y;

      const newXpct = Math.min(Math.max((newXpx / rect.width) * 100, 0), 100);
      const newYpct = Math.min(Math.max((newYpx / rect.height) * 100, 0), 100);

      if (dragTarget === 'overlay') {
        onUpdateOverlay({ overlayX: newXpct, overlayY: newYpct });
      } else if (dragTarget === 'logo') {
        onUpdateOverlay({ logoX: newXpct, logoY: newYpct });
      } else if (dragTarget === 'brand') {
        onUpdateOverlay({ brandNameX: newXpct, brandNameY: newYpct });
      }
    };

    const handleMouseUp = () => {
      setDragTarget(null);
    };

    if (dragTarget) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragTarget, dragOffset, onUpdateOverlay]);

  const getThemeStyles = () => {
    switch (config.theme) {
      case 'luxury':
        return {
          textMain: "text-amber-900",
          fontMain: "font-fashion font-bold italic",
          fontPrice: "font-sans font-black",
          accent: "text-red-600",
        };
      default:
        return {
          textMain: "text-slate-900",
          fontMain: "font-sans font-bold",
          fontPrice: "font-sans font-black",
          accent: "text-red-600",
        };
    }
  };

  const styles = getThemeStyles();

  // Styles for individual components
  const overlayWrapperStyle: React.CSSProperties = {
    position: 'absolute',
    left: `${config.overlayX}%`,
    top: `${config.overlayY}%`,
    transform: `translate(-50%, -50%) scale(${config.overlayScale})`,
    cursor: dragTarget === 'overlay' ? 'grabbing' : 'grab',
    userSelect: 'none',
    width: '100%',
    pointerEvents: 'auto',
    zIndex: 50
  };

  const logoStyle: React.CSSProperties = {
    position: 'absolute',
    left: `${config.logoX}%`,
    top: `${config.logoY}%`,
    transform: `translate(0, 0) scale(${config.logoScale})`,
    cursor: dragTarget === 'logo' ? 'grabbing' : 'grab',
    userSelect: 'none',
    pointerEvents: 'auto',
    zIndex: 40,
    filter: config.logoColor === 'white' ? 'brightness(0) invert(1)' : 'brightness(0)'
  };

  const brandNameStyle: React.CSSProperties = {
    position: 'absolute',
    left: `${config.brandNameX}%`,
    top: `${config.brandNameY}%`,
    transform: `translate(0, 0) scale(${config.brandNameScale})`,
    cursor: dragTarget === 'brand' ? 'grabbing' : 'grab',
    userSelect: 'none',
    pointerEvents: 'auto',
    zIndex: 41,
    color: config.logoColor === 'white' ? 'rgba(255,255,255,0.6)' : 'rgba(0,0,0,0.6)'
  };

  const getAspectClass = () => {
    switch (config.aspectRatio) {
      case '1:1': return 'aspect-square';
      case '4:5': return 'aspect-[4/5]';
      case '16:9': return 'aspect-[16/9]';
      case '9:16': return 'aspect-[9/16]';
      default: return 'aspect-[3/4]';
    }
  };

  return (
    <div 
      ref={containerRef}
      className={`relative w-full max-w-2xl mx-auto rounded-3xl overflow-hidden shadow-2xl bg-slate-900 ${getAspectClass()} group border border-white/5`}
    >
      <img src={image} alt="Fashion" className="w-full h-full object-cover" />
      <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent pointer-events-none"></div>

      {/* Draggable Logo */}
      {config.logo && (
        <div style={logoStyle} onMouseDown={(e) => handleMouseDown(e, 'logo')}>
          <img src={config.logo} className="h-10 object-contain" alt="Logo" />
        </div>
      )}

      {/* Draggable Brand Name */}
      <div style={brandNameStyle} onMouseDown={(e) => handleMouseDown(e, 'brand')}>
        <span className="text-[12px] font-black tracking-[0.5em] uppercase whitespace-nowrap">
          {config.brandName}
        </span>
      </div>

      {/* Draggable Main Overlay */}
      <div 
        style={overlayWrapperStyle}
        onMouseDown={(e) => handleMouseDown(e, 'overlay')}
        className="px-12 flex flex-col items-center text-center"
      >
        <div className="flex flex-col gap-4">
            <div className="flex items-center justify-center gap-4">
              <span className={`text-[12px] font-bold uppercase tracking-[0.6em] text-white opacity-80 font-fashion italic`}>
                {config.promotionSubtitle}
              </span>
              {config.discountPercentage && config.discountPercentage !== "0" && (
                <span className="bg-red-600 text-white px-3 py-0.5 text-[9px] font-black uppercase tracking-widest">-{config.discountPercentage}%</span>
              )}
            </div>
            <h2 className="text-6xl leading-[0.9] text-white font-fashion italic font-bold">
              SALE <span className="block text-4xl not-italic opacity-60 uppercase">{config.promotionText}</span>
            </h2>
            <div className="pt-4 flex flex-col items-center">
                  <span className="text-7xl font-black font-sans tracking-tighter text-red-600">
                    {formatPrice(config.salePrice)}<span className="text-3xl ml-1 font-bold">đ</span>
                  </span>
                  <span className="text-white/40 line-through text-lg font-bold">{formatPrice(config.originalPrice)}đ</span>
                {config.productCode && (
                   <span className="text-[9px] font-mono text-white/20 uppercase tracking-widest mt-4">{config.productCode}</span>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

