import React, { useState, useRef, useEffect } from 'react';
import { SaleConfig } from '../types';

interface PreviewCanvasProps {
  image: string;
  config: SaleConfig;
  onUpdateOverlay?: (updates: Partial<SaleConfig>) => void;
}

type DragTarget = 'logo' | 'brand' | 'headline' | 'promoText' | 'price' | 'code';

const PreviewCanvas: React.FC<PreviewCanvasProps> = ({ image, config, onUpdateOverlay }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragTarget, setDragTarget] = useState<DragTarget | null>(null);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const formatPrice = (price: string) => {
    if (!price) return "";
    const num = parseFloat(price.replace(/[^0-9]/g, ''));
    if (isNaN(num)) return price;
    if (num < 1000) return `${num}K`;
    return new Intl.NumberFormat('vi-VN').format(num);
  };

  const handleMouseDown = (e: React.MouseEvent, target: DragTarget) => {
    if (!containerRef.current || !onUpdateOverlay) return;

    e.stopPropagation();
    setDragTarget(target);
    const rect = containerRef.current.getBoundingClientRect();

    let currentX = 0, currentY = 0;
    switch(target) {
      case 'logo': currentX = config.logoX; currentY = config.logoY; break;
      case 'brand': currentX = config.brandNameX; currentY = config.brandNameY; break;
      case 'headline': currentX = config.headlineX; currentY = config.headlineY; break;
      case 'promoText': currentX = config.promoTextX; currentY = config.promoTextY; break;
      case 'price': currentX = config.priceX; currentY = config.priceY; break;
      case 'code': currentX = config.codeX; currentY = config.codeY; break;
    }

    const targetXpx = (currentX / 100) * rect.width;
    const targetYpx = (currentY / 100) * rect.height;

    setDragOffset({
      x: e.clientX - rect.left - targetXpx,
      y: e.clientY - rect.top - targetYpx
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragTarget || !containerRef.current || !onUpdateOverlay) return;

      const rect = containerRef.current.getBoundingClientRect();
      const newXpx = e.clientX - rect.left - dragOffset.x;
      const newYpx = e.clientY - rect.top - dragOffset.y;

      const newXpct = Math.min(Math.max((newXpx / rect.width) * 100, 0), 100);
      const newYpct = Math.min(Math.max((newYpx / rect.height) * 100, 0), 100);

      const updates: Partial<SaleConfig> = {};
      switch(dragTarget) {
        case 'logo': updates.logoX = newXpct; updates.logoY = newYpct; break;
        case 'brand': updates.brandNameX = newXpct; updates.brandNameY = newYpct; break;
        case 'headline': updates.headlineX = newXpct; updates.headlineY = newYpct; break;
        case 'promoText': updates.promoTextX = newXpct; updates.promoTextY = newYpct; break;
        case 'price': updates.priceX = newXpct; updates.priceY = newYpct; break;
        case 'code': updates.codeX = newXpct; updates.codeY = newYpct; break;
      }
      onUpdateOverlay(updates);
    };

    const handleMouseUp = () => setDragTarget(null);

    if (dragTarget) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragTarget, dragOffset, onUpdateOverlay]);

  const getCommonStyle = (x: number, y: number, scale: number, target: DragTarget): React.CSSProperties => ({
    position: 'absolute',
    left: `${x}%`,
    top: `${y}%`,
    transform: `translate(-50%, -50%) scale(${scale})`,
    cursor: dragTarget === target ? 'grabbing' : 'grab',
    userSelect: 'none',
    pointerEvents: 'auto',
    zIndex: dragTarget === target ? 100 : 50,
  });

  const getAspectClass = () => {
    switch (config.aspectRatio) {
      case '1:1': return 'aspect-square';
      case '4:5': return 'aspect-[4/5]';
      case '16:9': return 'aspect-[16/9]';
      case '9:16': return 'aspect-[9/16]';
      default: return 'aspect-[3/4]';
    }
  };

  const isLight = config.logoColor === 'white';

  return (
    <div 
      ref={containerRef}
      className={`relative w-full max-w-2xl mx-auto rounded-[40px] overflow-hidden shadow-2xl bg-[#0f1115] ${getAspectClass()} border border-white/5`}
    >
      <img src={image} alt="Fashion" className="w-full h-full object-cover select-none pointer-events-none" />
      <div className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-transparent pointer-events-none"></div>

      {/* 1. Logo */}
      {config.logo && (
        <div 
          style={{
            ...getCommonStyle(config.logoX, config.logoY, config.logoScale, 'logo'),
            filter: isLight ? 'brightness(0) invert(1)' : 'brightness(0)'
          }} 
          onMouseDown={(e) => handleMouseDown(e, 'logo')}
        >
          <img src={config.logo} className="h-12 object-contain" alt="Logo" />
        </div>
      )}

      {/* 2. Brand Name */}
      <div 
        style={{
          ...getCommonStyle(config.brandNameX, config.brandNameY, config.brandNameScale, 'brand'),
          color: isLight ? 'white' : 'black',
          opacity: 0.6
        }} 
        onMouseDown={(e) => handleMouseDown(e, 'brand')}
      >
        <span className="text-[14px] font-black tracking-[0.4em] uppercase whitespace-nowrap drop-shadow-sm font-fashion italic">
          {config.brandName}
        </span>
      </div>

      {/* 3. Headline */}
      <div 
        style={getCommonStyle(config.headlineX, config.headlineY, config.headlineScale, 'headline')}
        onMouseDown={(e) => handleMouseDown(e, 'headline')}
        className="flex items-center gap-4"
      >
        <div className="h-px w-8 bg-white/40"></div>
        <span className="text-[12px] md:text-[14px] font-bold uppercase tracking-[0.6em] text-white drop-shadow-lg font-fashion italic">
          {config.promotionSubtitle}
        </span>
        <div className="h-px w-8 bg-white/40"></div>
      </div>

      {/* 4. Promo Text */}
      <div 
        style={getCommonStyle(config.promoTextX, config.promoTextY, config.promoTextScale, 'promoText')}
        onMouseDown={(e) => handleMouseDown(e, 'promoText')}
      >
        <h2 className="text-4xl md:text-5xl font-black text-white uppercase drop-shadow-2xl font-fashion italic tracking-tight text-center">
          {config.promotionText}
        </h2>
      </div>

      {/* 5. Price Block */}
      <div 
        style={getCommonStyle(config.priceX, config.priceY, config.priceScale, 'price')}
        onMouseDown={(e) => handleMouseDown(e, 'price')}
        className="flex flex-col items-center gap-1"
      >
        <div className="flex items-baseline gap-4 bg-white/10 backdrop-blur-md px-8 py-4 rounded-full border border-white/20 shadow-2xl">
          <span className="text-6xl font-black font-sans tracking-tighter text-red-500 drop-shadow-lg">
            {formatPrice(config.salePrice)}<span className="text-3xl ml-1 font-bold">đ</span>
          </span>
          <span className="text-white/40 line-through text-xl font-bold font-sans drop-shadow-md">
            {formatPrice(config.originalPrice)}đ
          </span>
        </div>
      </div>

      {/* 6. Product SKU */}
      {config.productCode && (
        <div 
          style={{
            ...getCommonStyle(config.codeX, config.codeY, config.codeScale, 'code'),
            color: isLight ? 'white' : 'black',
            opacity: 0.3
          }} 
          onMouseDown={(e) => handleMouseDown(e, 'code')}
        >
          <span className="text-[10px] font-mono font-bold tracking-[0.5em] uppercase whitespace-nowrap">
            {config.productCode}
          </span>
        </div>
      )}
    </div>
  );
};

export default PreviewCanvas;

import React, { useState, useEffect } from 'react';
import { Upload, Trash2, Download, Settings2, Palette, Sparkles, Loader2, Wand2, RefreshCcw, Camera, Layout, Store, Scissors, Type as FontIcon, Maximize, Image as ImageIcon, Hash, Tag, CircleDollarSign, Move, SearchCode, Type } from 'lucide-react';
import { AppState, SaleConfig } from './types';
import { analyzeFashionImage, redesignBackground } from './services/geminiService';
import PreviewCanvas from './components/PreviewCanvas';
import AnalysisDisplay from './components/AnalysisDisplay';

const INITIAL_CONFIG: SaleConfig = {
  originalPrice: "1250000",
  salePrice: "199",
  discountPercentage: "80",
  brandName: "TUẤN STUDIO",
  productCode: "FSH-2025",
  logo: null,
  logoColor: 'white',
  promotionText: "TRÊN TOÀN HỆ THỐNG",
  promotionSubtitle: "SPECIAL OFFER",
  pricePrefix: "ĐỒNG GIÁ TỪ",
  bottomNote: "(*) SỐ LƯỢNG CÓ HẠN",
  theme: 'luxury',
  aspectRatio: '1:1',

  // Vị trí chuyên nghiệp mặc định
  logoX: 5, logoY: 5, logoScale: 1.0,
  brandNameX: 5, brandNameY: 10, brandNameScale: 1.0,
  headlineX: 50, headlineY: 65, headlineScale: 1.0,
  promoTextX: 50, promoTextY: 72, promoTextScale: 1.0,
  priceX: 50, priceY: 82, priceScale: 1.0,
  codeX: 95, codeY: 95, codeScale: 1.0
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    image: null,
    analysis: null,
    isAnalyzing: false,
    config: INITIAL_CONFIG,
  });
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [backgroundPrompt, setBackgroundPrompt] = useState("");

  const updateConfig = (updates: Partial<SaleConfig>) => {
    setState(prev => ({ ...prev, config: { ...prev.config, ...updates } }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = event.target?.result as string;
        setOriginalImage(base64);
        setState(prev => ({ ...prev, image: base64, analysis: null, isAnalyzing: true }));
        try {
          const result = await analyzeFashionImage(base64);
          setState(prev => ({ ...prev, analysis: result, isAnalyzing: false }));
        } catch (error) {
          setState(prev => ({ ...prev, isAnalyzing: false }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        updateConfig({ logo: event.target?.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const applyTheme = (prompt: string) => {
    setBackgroundPrompt(prompt);
  };

  const handleBackgroundRedesign = async () => {
    if (!originalImage) return;
    setIsGenerating(true);
    try {
      const finalPrompt = backgroundPrompt || (state.analysis ? `Luxury fashion studio, minimal aesthetic, lighting consistent with ${state.analysis.backgroundDna.lighting}` : "Luxury fashion studio background");
      const redesignedUrl = await redesignBackground(
        originalImage, 
        finalPrompt, 
        state.config.theme, 
        state.config.aspectRatio,
        state.analysis
      );
      setState(prev => ({ ...prev, image: redesignedUrl }));
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
