                  <input type="text" value={state.config.promotionSubtitle} onChange={(e) => updateConfig({ promotionSubtitle: e.target.value })} className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-3 text-sm font-fashion italic outline-none focus:border-red-500" />
                  <div className="flex items-center gap-3">
