          {/* Group 5: AI Redesign */}
          <section className="bg-red-500/5 p-6 rounded-[32px] border border-red-500/20 space-y-5 mb-10">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <Sparkles size={18} className="text-red-500" />
                  <h2 className="font-bold uppercase tracking-[0.2em] text-[10px] text-red-500">AI Redesign bối cảnh</h2>
