                  <div className="flex items-center gap-3">
                    <span className="text-[8px] text-white/20 uppercase font-bold">Size:</span>
                    <input type="range" min="0.5" max="3.0" step="0.1" value={state.config.headlineScale} onChange={(e) => updateConfig({ headlineScale: parseFloat(e.target.value) })} className="flex-1 accent-red-600 h-1" />
                  </div>
               </div>

               <div className="space-y-2">
                  <label className="text-[9px] font-black text-white/30 uppercase tracking-widest">Text phụ</label>
                  <input type="text" value={state.config.promotionText} onChange={(e) => updateConfig({ promotionText: e.target.value })} className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-3 text-sm outline-none focus:border-red-500" />
                  <div className="flex items-center gap-3">
                    <span className="text-[8px] text-white/20 uppercase font-bold">Size:</span>
                    <input type="range" min="0.5" max="3.0" step="0.1" value={state.config.promoTextScale} onChange={(e) => updateConfig({ promoTextScale: parseFloat(e.target.value) })} className="flex-1 accent-red-600 h-1" />
                  </div>
               </div>
            </div>
          </section>

          {/* Group 5: AI Redesign */}
          <section className="bg-red-500/5 p-6 rounded-[32px] border border-red-500/20 space-y-5 mb-10">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <Sparkles size={18} className="text-red-500" />
                  <h2 className="font-bold uppercase tracking-[0.2em] text-[10px] text-red-500">AI Redesign bối cảnh</h2>
                </div>
                {displayImage && (
                  <button onClick={handleBackgroundRedesign} className="flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest hover:bg-white hover:text-red-600 transition-all shadow-lg">
                    <Wand2 size={12} /> Redesign ảnh này
                  </button>
                )}
             </div>

             {state.analysis && (
               <div className="grid grid-cols-1 gap-2">
                 {state.analysis.suggestedThemes.map((theme, i) => (
                   <button key={i} onClick={() => applyTheme(theme.prompt)} className={`text-left p-3 rounded-2xl border transition-all ${backgroundPrompt === theme.prompt ? 'bg-red-600 border-red-600 text-white' : 'bg-black/40 border-white/5 text-white hover:border-red-500/50'}`}>
                     <p className="text-[10px] font-black uppercase tracking-widest mb-1">{theme.name}</p>
                     <p className={`text-[9px] opacity-60 italic ${backgroundPrompt === theme.prompt ? 'text-white/70' : ''}`}>{theme.description}</p>
                   </button>
                 ))}
               </div>
             )}
             <textarea value={backgroundPrompt} onChange={(e) => setBackgroundPrompt(e.target.value)} placeholder="Mô tả bối cảnh hoặc chọn gợi ý..." className="w-full bg-black/40 border border-white/10 rounded-2xl p-4 text-xs focus:border-red-500 outline-none transition-all min-h-[80px]" />
          </section>
        </div>
      </main>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; height: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.1); }
      `}</style>
    </div>
  );
};

export default App;

