import { GoogleGenAI, Type } from "@google/genai";
import { ImageAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeFashionImage = async (base64Image: string): Promise<ImageAnalysis> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image.split(',')[1],
          },
        },
        {
          text: "Phân tích chuyên sâu ảnh thời trang này. 1. Trích xuất ADN phong cách: đặc biệt tập trung vào kiểu dáng và chất liệu trang phục mẫu đang mặc (modelOutfitStyle). 2. Trích xuất ADN bối cảnh. 3. Đề xuất 3 chủ đề bối cảnh (suggestedThemes) để tôn vinh bộ đồ này nhất (ví dụ: bối cảnh dịu dàng cho đồ lụa, bối cảnh sang trọng hiện đại cho đồ công sở). Phản hồi bằng tiếng Việt dưới dạng JSON.",
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          styleDna: {
            type: Type.OBJECT,
            properties: {
              mood: { type: Type.STRING },
              vibe: { type: Type.STRING },
              colors: { type: Type.ARRAY, items: { type: Type.STRING } },
              fashionType: { type: Type.STRING },
              modelOutfitStyle: { type: Type.STRING },
            },
            required: ["mood", "vibe", "colors", "fashionType", "modelOutfitStyle"]
          },
          backgroundDna: {
            type: Type.OBJECT,
            properties: {
              lighting: { type: Type.STRING },
              texture: { type: Type.STRING },
              colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } },
              depthOfField: { type: Type.STRING },
              consistencyNote: { type: Type.STRING },
            },
            required: ["lighting", "texture", "colorPalette", "depthOfField", "consistencyNote"]
          },
          suggestedThemes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                prompt: { type: Type.STRING },
                description: { type: Type.STRING },
              },
              required: ["name", "prompt", "description"]
            }
          },
          recommendations: {
            type: Type.OBJECT,
            properties: {
              font: { type: Type.STRING },
              bannerColor: { type: Type.STRING },
              layout: { type: Type.STRING },
            },
            required: ["font", "bannerColor", "layout"]
          },
        },
        required: ["styleDna", "backgroundDna", "suggestedThemes", "recommendations"],
      },
    },
  });

  // response.text is a getter property.
  const text = response.text;
  if (!text) throw new Error("Empty response from AI");
  return JSON.parse(text.trim());
};

export const redesignBackground = async (
  originalImage: string, 
  backgroundPrompt: string, 
  theme: string, 
  aspectRatio: string,
  analysis?: ImageAnalysis | null
): Promise<string> => {
  const dnaContext = analysis ? 
    `Focus on: ${analysis.backgroundDna.lighting} lighting, emphasizing the ${analysis.styleDna.modelOutfitStyle} of the garment.` : "";

  const outpaintInstructions = aspectRatio === '16:9' 
    ? "TASK: AI OUTPAINTING. Keep the model and garment perfectly intact in the center. Expand the environment horizontally to 16:9 while matching the analyzed fashion style."
    : "Re-envision the background to be high-end while keeping the model and outfit unchanged.";

  const fullPrompt = `${outpaintInstructions} ${dnaContext} New background style: ${backgroundPrompt}. Theme: ${theme}. Professional high-fashion editorial lighting. 8k resolution. NO text.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: originalImage.split(',')[1],
          },
        },
        { text: fullPrompt }
      ]
    },
    config: {
      imageConfig: {
        aspectRatio: aspectRatio as any
      }
    }
  });

  // Iterate through parts to find the image part as recommended.
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Generation failed");
};

