                  <label className="text-[9px] font-black text-white/30 uppercase tracking-widest">Headline</label>
                  <input type="text" value={state.config.promotionSubtitle} onChange={(e) => updateConfig({ promotionSubtitle: e.target.value })} className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-3 text-sm font-fashion italic outline-none focus:border-red-500" />
                  <div className="flex items-center gap-3">
                    <span className="text-[8px] text-white/20 uppercase font-bold">Size:</span>
                    <input type="range" min="0.5" max="3.0" step="0.1" value={state.config.headlineScale} onChange={(e) => updateConfig({ headlineScale: parseFloat(e.target.value) })} className="flex-1 accent-red-600 h-1" />
                  </div>
               </div>

               <div className="space-y-2">
                  <label className="text-[9px] font-black text-white/30 uppercase tracking-widest">Text phụ</label>
                  <input type="text" value={state.config.promotionText} onChange={(e) => updateConfig({ promotionText: e.target.value })} className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-3 text-sm outline-none focus:border-red-500" />
                  <div className="flex items-center gap-3">
                    <span className="text-[8px] text-white/20 uppercase font-bold">Size:</span>
                    <input type="range" min="0.5" max="3.0" step="0.1" value={state.config.promoTextScale} onChange={(e) => updateConfig({ promoTextScale: parseFloat(e.target.value) })} className="flex-1 accent-red-600 h-1" />
