import React, { useState, useRef, useEffect } from 'react';
import { SaleConfig, SaleItem } from '../types';

interface PreviewCanvasProps {
  image: string;
  config: SaleConfig;
  item: SaleItem;
  onUpdateOverlay?: (updates: Partial<SaleConfig>) => void;
}

type DragTarget = 'logo' | 'brand' | 'headline' | 'promoText' | 'price' | 'code';

const PreviewCanvas: React.FC<PreviewCanvasProps> = ({ image, config, item, onUpdateOverlay }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragTarget, setDragTarget] = useState<DragTarget | null>(null);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const formatPrice = (price: string) => {
    if (!price) return "";
    const num = parseFloat(price.replace(/[^0-9]/g, ''));
    if (isNaN(num)) return price;
    if (num < 1000) return `${num}K`;
    return new Intl.NumberFormat('vi-VN').format(num);
  };

  const handleMouseDown = (e: React.MouseEvent, target: DragTarget) => {
    if (!containerRef.current || !onUpdateOverlay) return;

    e.stopPropagation();
    setDragTarget(target);
    const rect = containerRef.current.getBoundingClientRect();

    let currentX = 0, currentY = 0;
    switch(target) {
      case 'logo': currentX = config.logoX; currentY = config.logoY; break;
      case 'brand': currentX = config.brandNameX; currentY = config.brandNameY; break;
      case 'headline': currentX = config.headlineX; currentY = config.headlineY; break;
      case 'promoText': currentX = config.promoTextX; currentY = config.promoTextY; break;
      case 'price': currentX = config.priceX; currentY = config.priceY; break;
      case 'code': currentX = config.codeX; currentY = config.codeY; break;
    }

    const targetXpx = (currentX / 100) * rect.width;
    const targetYpx = (currentY / 100) * rect.height;

    setDragOffset({
      x: e.clientX - rect.left - targetXpx,
      y: e.clientY - rect.top - targetYpx
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!dragTarget || !containerRef.current || !onUpdateOverlay) return;

      const rect = containerRef.current.getBoundingClientRect();
      const newXpx = e.clientX - rect.left - dragOffset.x;
      const newYpx = e.clientY - rect.top - dragOffset.y;

      const newXpct = Math.min(Math.max((newXpx / rect.width) * 100, 0), 100);
      const newYpct = Math.min(Math.max((newYpx / rect.height) * 100, 0), 100);

      const updates: Partial<SaleConfig> = {};
      switch(dragTarget) {
        case 'logo': updates.logoX = newXpct; updates.logoY = newYpct; break;
        case 'brand': updates.brandNameX = newXpct; updates.brandNameY = newYpct; break;
        case 'headline': updates.headlineX = newXpct; updates.headlineY = newYpct; break;
        case 'promoText': updates.promoTextX = newXpct; updates.promoTextY = newYpct; break;
        case 'price': updates.priceX = newXpct; updates.priceY = newYpct; break;
        case 'code': updates.codeX = newXpct; updates.codeY = newYpct; break;
      }
      onUpdateOverlay(updates);
    };

    const handleMouseUp = () => setDragTarget(null);

    if (dragTarget) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [dragTarget, dragOffset, onUpdateOverlay]);

  const getCommonStyle = (x: number, y: number, scale: number, target: DragTarget): React.CSSProperties => ({
    position: 'absolute',
    left: `${x}%`,
    top: `${y}%`,
    transform: `translate(-50%, -50%) scale(${scale})`,
    cursor: dragTarget === target ? 'grabbing' : 'grab',
    userSelect: 'none',
    pointerEvents: 'auto',
    zIndex: dragTarget === target ? 100 : 50,
  });

  const getAspectClass = () => {
    switch (config.aspectRatio) {
      case '1:1': return 'aspect-square';
      case '4:3': return 'aspect-[4/3]';
      case '16:9': return 'aspect-[16/9]';
      case '9:16': return 'aspect-[9/16]';
      default: return 'aspect-[3/4]';
    }
  };

  const isLight = config.logoColor === 'white';

  return (
    <div 
      ref={containerRef}
      className={`relative w-full mx-auto rounded-[5%] overflow-hidden shadow-2xl bg-[#0f1115] ${getAspectClass()} border border-white/5 transition-all duration-500`}
      style={{ containerType: 'inline-size' }}
    >
      <img src={image} alt="Fashion" className="w-full h-full object-cover select-none pointer-events-none" />
      <div className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-transparent pointer-events-none"></div>

      {config.logo && (
        <div 
          style={{
            ...getCommonStyle(config.logoX, config.logoY, config.logoScale, 'logo'),
            filter: isLight ? 'brightness(0) invert(1)' : 'brightness(0)'
          }} 
          onMouseDown={(e) => handleMouseDown(e, 'logo')}
        >
          <img src={config.logo} style={{ height: '5cqw' }} className="object-contain" alt="Logo" />
        </div>
      )}

      <div 
        style={{
          ...getCommonStyle(config.brandNameX, config.brandNameY, config.brandNameScale, 'brand'),
          color: isLight ? 'white' : 'black',
          opacity: 0.6,
          fontSize: '1.4cqw'
        }} 
        onMouseDown={(e) => handleMouseDown(e, 'brand')}
      >
        <span className="font-black tracking-[0.4em] uppercase whitespace-nowrap drop-shadow-sm font-fashion italic">
          {config.brandName}
        </span>
      </div>

      <div 
        style={getCommonStyle(config.headlineX, config.headlineY, config.headlineScale, 'headline')}
        onMouseDown={(e) => handleMouseDown(e, 'headline')}
        className="flex items-center"
        style={{ ...getCommonStyle(config.headlineX, config.headlineY, config.headlineScale, 'headline'), gap: '1cqw' }}
      >
        <div style={{ height: '1px', width: '3cqw', backgroundColor: 'rgba(255,255,255,0.4)' }}></div>
        <span style={{ fontSize: '1.3cqw' }} className="font-bold uppercase tracking-[0.6em] text-white drop-shadow-lg font-fashion italic whitespace-nowrap">
          {config.promotionSubtitle}
        </span>
        <div style={{ height: '1px', width: '3cqw', backgroundColor: 'rgba(255,255,255,0.4)' }}></div>
      </div>

      <div 
        style={getCommonStyle(config.promoTextX, config.promoTextY, config.promoTextScale, 'promoText')}
        onMouseDown={(e) => handleMouseDown(e, 'promoText')}
      >
        <h2 style={{ fontSize: '5cqw' }} className="font-black text-white uppercase drop-shadow-2xl font-fashion italic tracking-tight text-center whitespace-nowrap">
          {config.promotionText}
        </h2>
      </div>

      {/* Price Block - Updated with container units (cqw) for proportional scaling */}
      <div 
        style={getCommonStyle(config.priceX, config.priceY, config.priceScale, 'price')}
        onMouseDown={(e) => handleMouseDown(e, 'price')}
        className="flex flex-col items-center"
      >
        <div 
          style={{ 
            padding: config.showPriceBackground ? '2cqw 6cqw' : '0',
            borderRadius: '9999px',
            gap: '1.5cqw'
          }}
          className={`flex items-baseline transition-all duration-300 ${config.showPriceBackground ? 'bg-white/10 backdrop-blur-xl border border-white/20 shadow-[0_20px_50px_rgba(0,0,0,0.3)]' : ''}`}
        >
          <span 
            style={{ fontSize: '8cqw' }}
            className={`font-black font-sans tracking-tighter text-red-500 whitespace-nowrap ${!config.showPriceBackground ? 'drop-shadow-[0_2px_10px_rgba(0,0,0,0.8)]' : 'drop-shadow-lg'}`}
          >
            {formatPrice(item.salePrice)}<span style={{ fontSize: '3cqw' }} className="ml-0.5 font-bold">đ</span>
          </span>
          <span 
            style={{ fontSize: '2.5cqw' }}
            className={`line-through font-bold font-sans whitespace-nowrap ${config.showPriceBackground ? 'text-white/40 drop-shadow-md' : 'text-white/60 drop-shadow-[0_2px_5px_rgba(0,0,0,0.8)]'}`}
          >
            {formatPrice(item.originalPrice)}đ
          </span>
        </div>
      </div>

      {item.productCode && (
        <div 
          style={{
            ...getCommonStyle(config.codeX, config.codeY, config.codeScale, 'code'),
            color: isLight ? 'white' : 'black',
            opacity: 0.3,
            fontSize: '1cqw'
          }} 
          onMouseDown={(e) => handleMouseDown(e, 'code')}
        >
          <span className="font-mono font-bold tracking-[0.5em] uppercase whitespace-nowrap">
            {item.productCode}
          </span>
        </div>
      )}
    </div>
  );
};

export default PreviewCanvas;

