             <textarea value={backgroundPrompt} onChange={(e) => setBackgroundPrompt(e.target.value)} placeholder="Mô tả bối cảnh..." className="w-full bg-black/40 border border-white/10 rounded-2xl p-4 text-xs focus:border-red-500 outline-none transition-all min-h-[80px]" />
