        <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-xl flex flex-col items-center justify-center">
          <div className="w-24 h-24 mb-8 relative">
            <Loader2 size={96} className="text-red-500 animate-spin" />
            <div className="absolute inset-0 flex items-center justify-center font-black text-xs">
              {Math.round((exportProgress.current / exportProgress.total) * 100)}%
            </div>
          </div>
          <h2 className="text-3xl font-fashion italic mb-2">Đang xuất bản ảnh hàng loạt...</h2>
          <p className="text-white/40 text-[10px] font-black uppercase tracking-[0.4em]">
            Đã xử lý {exportProgress.current} / {exportProgress.total} sản phẩm
          </p>
          <div className="mt-8 w-64 h-1 bg-white/10 rounded-full overflow-hidden">
             <div 
               className="h-full bg-red-500 transition-all duration-300" 
               style={{ width: `${(exportProgress.current / exportProgress.total) * 100}%` }}
             ></div>
          </div>
        </div>
      )}

      <header className="border-b border-white/5 bg-black/40 backdrop-blur-3xl z-50 flex-shrink-0">
        <div className="w-full px-8 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-gradient-to-tr from-amber-500 to-yellow-200 rounded-full flex items-center justify-center shadow-[0_0_20px_rgba(251,191,36,0.3)]">
              <Sparkles size={20} className="text-black" />
            </div>
            <div>
              <h1 className="font-fashion text-xl md:text-2xl font-bold tracking-tight">TUẤN DZ <span className="text-[9px] font-sans bg-white text-black px-1.5 py-0.5 ml-1 rounded font-black">AI STUDIO</span></h1>
              <p className="text-[8px] uppercase tracking-[0.4em] text-white/30 font-bold">Fashion Ad Design specialist</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <div className="px-4 py-2 bg-white/5 rounded-full border border-white/10 flex items-center gap-3">
               <Package size={14} className="text-amber-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">{state.items.length} SẢN PHẨM</span>
             </div>
             <button onClick={() => window.location.reload()} className="p-3 text-white/20 hover:text-white transition-all">
               <RefreshCcw size={18} />
             </button>
             <button 
               onClick={handleExportAll}
               disabled={!state.image || isExporting}
               className={`bg-white text-black px-6 py-3 rounded-full font-black text-[10px] tracking-[0.2em] transition-all shadow-xl active:scale-95 flex items-center gap-2 ${(!state.image || isExporting) ? 'opacity-50 cursor-not-allowed' : 'hover:bg-red-600 hover:text-white'}`}
             >
                <Download size={14} /> XUẤT TOÀN BỘ ({state.items.length})
             </button>
          </div>
        </div>
      </header>

      <main className="flex-grow w-full flex overflow-hidden">
        <div className="flex-grow bg-[#14151a] relative flex flex-col items-center overflow-y-auto custom-scrollbar pt-8 pb-12 px-12">
          {!state.image && !isGenerating ? (
            <div className="w-full flex-grow flex items-center justify-center">
              <div className="w-full max-w-2xl aspect-square rounded-[50px] border-2 border-dashed border-white/10 bg-white/5 flex flex-col items-center justify-center gap-10 group cursor-pointer relative overflow-hidden transition-all hover:bg-white/[0.07] hover:border-red-500/50">
                 <input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer z-10" onChange={handleImageUpload} />
                 <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center text-white/10 group-hover:scale-110 group-hover:text-red-500 transition-all border border-white/5 shadow-inner">
                   <Files size={40} />
                 </div>
                 <div className="text-center z-10 space-y-3 px-10">
                   <p className="text-2xl font-fashion italic">Tải Hàng Loạt Ảnh</p>
                   <p className="text-[10px] text-white/20 uppercase tracking-[0.3em] font-bold">Chọn nhiều ảnh cùng lúc, AI sẽ xử lý bối cảnh cho từng tấm</p>
                 </div>
              </div>
