                    <button onClick={() => updateConfig({ logoColor: 'black' })} className={`flex-1 py-1.5 rounded-lg text-[8px] font-black uppercase border ${state.config.logoColor === 'black' ? 'bg-black text-white border-white/20' : 'bg-transparent text-white/20 border-white/5'}`}>Đen</button>
