                   <button key={i} onClick={() => applyTheme(theme.prompt)} className={`text-left p-3 rounded-2xl border transition-all ${backgroundPrompt === theme.prompt ? 'bg-red-600 border-red-600 text-white' : 'bg-black/40 border-white/5 text-white hover:border-red-500/50'}`}>
