                  <label className="text-[8px] font-black text-white/20 uppercase tracking-widest">Headline (Chính)</label>
                  <input 
                    type="text" 
                    value={state.config.promotionText} 
                    onChange={(e) => updateConfig({ promotionText: e.target.value })}
                    className="w-full bg-black/40 border border-white/5 rounded-xl px-4 py-3 text-sm font-fashion font-bold italic outline-none focus:border-amber-500/50"
