                  </div>
               </div>

               <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-white/20 uppercase tracking-widest">Tiền tố giá</label>
                    <input 
                      type="text" 
                      value={state.config.pricePrefix} 
                      onChange={(e) => updateConfig({ pricePrefix: e.target.value })}
                      className="w-full bg-black/40 border border-white/5 rounded-xl px-3 py-2 text-[10px] outline-none focus:border-amber-500/50"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-white/20 uppercase tracking-widest">Ghi chú chân</label>
