export const exportItemAsImage = async (item: SaleItem, config: SaleConfig): Promise<void> => {
  return new Promise(async (resolve, reject) => {
    try {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = item.image || "";

      await new Promise((res) => (img.onload = res));

      // Xác định kích thước ảnh xuất (High Resolution)
      const baseWidth = 2048;
      let canvasHeight = baseWidth;
      const ratio = config.aspectRatio;

      if (ratio === '3:4') canvasHeight = baseWidth * (4/3);
      else if (ratio === '4:3') canvasHeight = baseWidth * (3/4);
      else if (ratio === '16:9') canvasHeight = baseWidth * (9/16);
      else if (ratio === '9:16') canvasHeight = baseWidth * (16/9);

      const canvas = document.createElement('canvas');
      canvas.width = baseWidth;
      canvas.height = canvasHeight;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject("Canvas context not available");

      // 1. Vẽ ảnh gốc
      ctx.drawImage(img, 0, 0, baseWidth, canvasHeight);

      // 2. Vẽ Gradient overlay phía dưới để text rõ hơn
      const gradient = ctx.createLinearGradient(0, canvasHeight * 0.7, 0, canvasHeight);
      gradient.addColorStop(0, 'transparent');
      gradient.addColorStop(1, 'rgba(0,0,0,0.5)');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, baseWidth, canvasHeight);

      // Helper để tính toán vị trí theo %
      const getX = (pct: number) => (pct / 100) * baseWidth;
      const getY = (pct: number) => (pct / 100) * canvasHeight;
      const getS = (size: number) => (size / 100) * baseWidth; // Cqw equivalent

      // Đảm bảo font đã load
      await document.fonts.load('bold 100px Inter');
      await document.fonts.load('italic 100px "Cormorant Garamond"');

      const isLight = config.logoColor === 'white';

      // 3. Vẽ Logo
      if (config.logo) {
        const logoImg = new Image();
        logoImg.src = config.logo;
        await new Promise((res) => (logoImg.onload = res));

        const logoHeight = getS(5) * config.logoScale;
        const logoWidth = (logoImg.width / logoImg.height) * logoHeight;

        ctx.save();
        ctx.drawImage(
            logoImg, 
            getX(config.logoX) - logoWidth / 2, 
            getY(config.logoY) - logoHeight / 2, 
            logoWidth, 
            logoHeight
        );
        ctx.restore();
      }

      // 4. Vẽ Tên Brand
      ctx.save();
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = isLight ? 'rgba(255,255,255,0.6)' : 'rgba(0,0,0,0.6)';
      ctx.font = `italic 900 ${getS(1.4) * config.brandNameScale}px "Cormorant Garamond"`;
      ctx.fillText(config.brandName.toUpperCase(), getX(config.brandNameX), getY(config.brandNameY));
      ctx.restore();

      // 5. Vẽ Headline (Promotion Subtitle)
      ctx.save();
      const headFontSize = getS(1.3) * config.headlineScale;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = 'white';
      ctx.font = `italic bold ${headFontSize}px "Cormorant Garamond"`;
      const headX = getX(config.headlineX);
      const headY = getY(config.headlineY);
      ctx.fillText(config.promotionSubtitle.toUpperCase(), headX, headY);

      // Vẽ line 2 bên headline
      const textWidth = ctx.measureText(config.promotionSubtitle.toUpperCase()).width;
      const lineWidth = getS(3);
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(headX - textWidth/2 - lineWidth - 10, headY);
      ctx.lineTo(headX - textWidth/2 - 10, headY);
      ctx.moveTo(headX + textWidth/2 + 10, headY);
      ctx.lineTo(headX + textWidth/2 + lineWidth + 10, headY);
      ctx.stroke();
      ctx.restore();

      // 6. Vẽ Promo Text (Headline lớn)
      ctx.save();
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = 'white';
      ctx.font = `italic 900 ${getS(5) * config.promoTextScale}px "Cormorant Garamond"`;
      ctx.shadowBlur = 20;
      ctx.shadowColor = 'black';
      ctx.fillText(config.promotionText.toUpperCase(), getX(config.promoTextX), getY(config.promoTextY));
      ctx.restore();

      // 6.1 Vẽ Price Prefix
      if (config.pricePrefix) {
        ctx.save();
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillStyle = 'white';
        ctx.font = `bold ${getS(1.2) * config.pricePrefixScale}px "Cormorant Garamond"`;
        ctx.fillText(config.pricePrefix.toUpperCase(), getX(config.pricePrefixX), getY(config.pricePrefixY));
        ctx.restore();
      }

      // 7. Vẽ Khối Giá
      ctx.save();
      const priceX = getX(config.priceX);
      const priceY = getY(config.priceY);
      const salePriceStr = `${item.salePrice}đ`;
      const oldPriceStr = `${item.originalPrice}đ`;

      ctx.font = `black ${getS(8) * config.priceScale}px Inter`;
      const saleWidth = ctx.measureText(salePriceStr).width;
      ctx.font = `bold ${getS(2.5) * config.priceScale}px Inter`;
      const oldWidth = ctx.measureText(oldPriceStr).width;

      const totalContentWidth = saleWidth + oldWidth + getS(1.5);
      const paddingH = getS(6);

      if (config.showPriceBackground) {
        ctx.fillStyle = 'rgba(255,255,255,0.1)';
        ctx.beginPath();
        const rectW = totalContentWidth + paddingH * 2;
        const rectH = getS(10) * config.priceScale;
        ctx.roundRect(priceX - rectW/2, priceY - rectH/2, rectW, rectH, 999);
        ctx.fill();
        ctx.strokeStyle = 'rgba(255,255,255,0.2)';
        ctx.stroke();
      }

      ctx.textAlign = 'left';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = '#ef4444'; 
      ctx.font = `900 ${getS(8) * config.priceScale}px Inter`;
      ctx.fillText(salePriceStr, priceX - totalContentWidth/2, priceY);

      ctx.fillStyle = 'rgba(255,255,255,0.5)';
      ctx.font = `bold ${getS(2.5) * config.priceScale}px Inter`;
      const oldX = priceX - totalContentWidth/2 + saleWidth + getS(1.5);
      ctx.fillText(oldPriceStr, oldX, priceY);

      const metrics = ctx.measureText(oldPriceStr);
      ctx.strokeStyle = 'rgba(255,255,255,0.5)';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(oldX, priceY);
      ctx.lineTo(oldX + metrics.width, priceY);
      ctx.stroke();
      ctx.restore();

      // 7.1 Vẽ Bottom Note
      if (config.bottomNote) {
        ctx.save();
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillStyle = 'rgba(255,255,255,0.7)';
        ctx.font = `italic bold ${getS(0.9) * config.bottomNoteScale}px Inter`;
        ctx.fillText(config.bottomNote.toUpperCase(), getX(config.bottomNoteX), getY(config.bottomNoteY));
        ctx.restore();
      }

      // 8. Vẽ SKU/Code
      if (item.productCode) {
        ctx.save();
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillStyle = isLight ? 'rgba(255,255,255,0.3)' : 'rgba(0,0,0,0.3)';
        ctx.font = `bold ${getS(1) * config.codeScale}px monospace`;
        ctx.fillText(item.productCode.toUpperCase(), getX(config.codeX), getY(config.codeY));
        ctx.restore();
      }

      // 9. Download
      const link = document.createElement('a');
      link.download = `SALE_${item.productCode || 'IMAGE'}_${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png', 1.0);
      link.click();

      resolve();
    } catch (e) {
      reject(e);
    }
  });
};

