            </div>
            <div className="grid grid-cols-5 gap-2">
              {(['1:1', '3:4', '4:3', '9:16', '16:9'] as const).map(ratio => (
                <button key={ratio} onClick={() => updateConfig({ aspectRatio: ratio })} className={`py-3 rounded-xl text-[9px] font-black transition-all border ${state.config.aspectRatio === ratio ? 'bg-red-600 text-white border-red-600' : 'bg-transparent text-white/20 border-white/5'}`}>
                  {ratio}
                </button>
              ))}
            </div>
          </section>

          {/* Branding */}
          <section className="bg-white/5 p-6 rounded-[32px] border border-white/10 space-y-5">
            <div className="flex items-center gap-3 border-b border-white/5 pb-3">
              <Store size={18} className="text-white/40" />
              <h2 className="font-bold uppercase tracking-[0.2em] text-[10px]">Thương hiệu</h2>
            </div>
            <div className="grid grid-cols-2 gap-4">
               <div className="space-y-3">
                  <div className="relative h-16 bg-black/40 border border-white/10 rounded-2xl flex items-center justify-center group cursor-pointer overflow-hidden">
                    <input type="file" className="absolute inset-0 opacity-0 cursor-pointer z-10" onChange={handleLogoUpload} />
                    {state.config.logo ? <img src={state.config.logo} className={`h-8 object-contain ${state.config.logoColor === 'white' ? 'invert opacity-80' : ''}`} /> : <ImageIcon className="text-white/10" />}
                  </div>
                  <div className="flex gap-1">
                    <button onClick={() => updateConfig({ logoColor: 'white' })} className={`flex-1 py-1.5 rounded-lg text-[8px] font-black uppercase border ${state.config.logoColor === 'white' ? 'bg-white text-black' : 'text-white/20 border-white/5'}`}>Trắng</button>
                    <button onClick={() => updateConfig({ logoColor: 'black' })} className={`flex-1 py-1.5 rounded-lg text-[8px] font-black uppercase border ${state.config.logoColor === 'black' ? 'bg-black text-white' : 'text-white/20 border-white/5'}`}>Đen</button>
                  </div>
               </div>
               <div className="space-y-3">
                  <input type="text" value={state.config.brandName} onChange={(e) => updateConfig({ brandName: e.target.value })} className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-3 h-16 text-xs font-fashion font-bold uppercase tracking-widest outline-none" placeholder="SHOP NAME" />
                  <input type="range" min="0.5" max="2.5" step="0.1" value={state.config.brandNameScale} onChange={(e) => updateConfig({ brandNameScale: parseFloat(e.target.value) })} className="w-full accent-red-600 h-1" />
               </div>
            </div>
          </section>

        </div>
      </main>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; height: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.1); }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Upload, Trash2, Download, Settings2, Palette, Sparkles, Loader2, Wand2, RefreshCcw, Camera, Layout, Store, Scissors, Type as FontIcon, Maximize, ImageIcon, Hash, Tag, CircleDollarSign, Move, SearchCode, Plus, Layers, Package, ListPlus, Files, ToggleLeft, ToggleRight, CheckCircle2, AlignCenter, Eye, RotateCcw, Sparkle, XCircle } from 'lucide-react';
import { AppState, SaleConfig, SaleItem } from './types';
import { analyzeFashionImage, redesignBackground } from './services/geminiService';
import { exportItemAsImage } from './services/exportService';
import PreviewCanvas from './components/PreviewCanvas';
import AnalysisDisplay from './components/AnalysisDisplay';

const INITIAL_CONFIG: SaleConfig = {
  brandName: "TUẤN STUDIO",
  logo: null,
  logoColor: 'white',
  promotionText: "TRÊN TOÀN HỆ THỐNG",
  promotionSubtitle: "SPECIAL OFFER",
  pricePrefix: "ĐỒNG GIÁ TỪ",
  bottomNote: "(*) SỐ LƯỢNG CÓ HẠN",
  theme: 'luxury',
  aspectRatio: '1:1',
  showPriceBackground: true, 

  logoX: 5, logoY: 5, logoScale: 1.0,
  brandNameX: 5, brandNameY: 10, brandNameScale: 1.0,
  headlineX: 50, headlineY: 65, headlineScale: 1.0,
  promoTextX: 50, promoTextY: 72, promoTextScale: 1.0,
  priceX: 50, priceY: 82, priceScale: 1.0,
  pricePrefixX: 50, pricePrefixY: 78, pricePrefixScale: 1.0,
  bottomNoteX: 50, bottomNoteY: 90, bottomNoteScale: 1.0,
  codeX: 95, codeY: 95, codeScale: 1.0
};

const DEFAULT_ITEM: SaleItem = {
  id: '1',
  originalPrice: "1250000",
  salePrice: "199",
  productCode: "FSH-2025",
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    image: null,
    analysis: null,
    isAnalyzing: false,
    config: INITIAL_CONFIG,
    items: [DEFAULT_ITEM],
    selectedItemId: '1',
    showAIDashboard: true,
  });

  const [isGenerating, setIsGenerating] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState({ current: 0, total: 0 });
  const [backgroundPrompt, setBackgroundPrompt] = useState("");
  const [isComparing, setIsComparing] = useState(false);

  const updateConfig = (updates: Partial<SaleConfig>) => {
    setState(prev => ({ ...prev, config: { ...prev.config, ...updates } }));
  };

  const updateItem = (id: string, updates: Partial<SaleItem>) => {
    setState(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, ...updates } : item)
    }));
  };

  const handleExportAll = async () => {
    if (state.items.length === 0) return;
    setIsExporting(true);
    setExportProgress({ current: 0, total: state.items.length });

    try {
      for (let i = 0; i < state.items.length; i++) {
        setExportProgress(prev => ({ ...prev, current: i + 1 }));
        await exportItemAsImage(state.items[i], state.config);
        await new Promise(r => setTimeout(r, 500));
      }
    } catch (error) {
      console.error("Export failed:", error);
      alert("Có lỗi khi xuất ảnh. Vui lòng thử lại.");
    } finally {
      setIsExporting(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const fileList = Array.from(files) as File[];
    setIsGenerating(true);

    try {
      const newItems: SaleItem[] = [];
      const readFileAsDataURL = (file: File): Promise<string> => {
        return new Promise((resolve) => {
          const reader = new FileReader();
          reader.onload = (e) => resolve(e.target?.result as string);
          reader.readAsDataURL(file);
        });
      };

      for (let i = 0; i < fileList.length; i++) {
        const base64 = await readFileAsDataURL(fileList[i]);
        const newId = Math.random().toString(36).substr(2, 9);

        newItems.push({
          id: newId,
          originalPrice: state.items[0]?.originalPrice || "1250000",
          salePrice: state.items[0]?.salePrice || "199",
          productCode: `FSH-${2025 + i}`,
          image: base64,
          originalImage: base64 // Lưu lại ảnh gốc khi upload
        });
      }

      setState(prev => ({
        ...prev,
        image: prev.image || newItems[0].image || null,
        items: prev.image ? [...prev.items, ...newItems] : newItems,
        selectedItemId: newItems[0].id,
        isAnalyzing: !prev.image
      }));

      if (!state.image && newItems[0]?.image) {
        const result = await analyzeFashionImage(newItems[0].image);
        setState(prev => ({ ...prev, analysis: result, isAnalyzing: false }));
      }

    } catch (error) {
      console.error("Upload error:", error);
      setState(prev => ({ ...prev, isAnalyzing: false }));
    } finally {
      setIsGenerating(false);
    }
  };

  // Added handleLogoUpload to handle brand logo selection
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      updateConfig({ logo: base64 });
    };
    reader.readAsDataURL(file);
  };

  const handleBackgroundRedesign = async () => {
    const currentItem = state.items.find(i => i.id === state.selectedItemId);
    const imgToProcess = currentItem?.image || state.image;

    if (!imgToProcess) return;

    setIsGenerating(true);
    try {
      const finalPrompt = backgroundPrompt || (state.analysis ? `Luxury fashion studio, minimal aesthetic, lighting consistent with ${state.analysis.backgroundDna.lighting}` : "Luxury fashion studio background");
      const redesignedUrl = await redesignBackground(
        imgToProcess, 
        finalPrompt, 
        state.config.theme, 
        state.config.aspectRatio,
        state.analysis
      );

      updateItem(state.selectedItemId, { image: redesignedUrl });
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRevert = () => {
    const currentItem = state.items.find(i => i.id === state.selectedItemId);
    if (currentItem?.originalImage) {
      updateItem(state.selectedItemId, { image: currentItem.originalImage });
    }
  };

  const applyTheme = (prompt: string) => {
    setBackgroundPrompt(prompt);
  };

  const removeItem = (id: string) => {
    if (state.items.length <= 1) return;
    setState(prev => {
      const newItems = prev.items.filter(item => item.id !== id);
      const nextId = id === prev.selectedItemId ? newItems[0].id : prev.selectedItemId;
      return {
        ...prev,
        items: newItems,
        selectedItemId: nextId,
        image: prev.selectedItemId === id ? (newItems.find(i => i.id === nextId)?.image || prev.image) : prev.image
      };
    });
  };

  const selectedItem = state.items.find(i => i.id === state.selectedItemId) || state.items[0];
  const displayImage = isComparing ? (selectedItem?.originalImage || selectedItem?.image || "") : (selectedItem?.image || state.image || "");

  return (
    <div className="min-h-screen bg-[#0a0b0d] text-white/90 overflow-hidden flex flex-col">
      {isExporting && (
        <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-xl flex flex-col items-center justify-center">
          <div className="w-24 h-24 mb-8 relative">
            <Loader2 size={96} className="text-red-500 animate-spin" />
            <div className="absolute inset-0 flex items-center justify-center font-black text-xs">
              {Math.round((exportProgress.current / exportProgress.total) * 100)}%
            </div>
          </div>
          <h2 className="text-3xl font-fashion italic mb-2">Đang xuất bản ảnh hàng loạt...</h2>
          <p className="text-white/40 text-[10px] font-black uppercase tracking-[0.4em]">
            Đã xử lý {exportProgress.current} / {exportProgress.total} sản phẩm
          </p>
        </div>
      )}

      <header className="border-b border-white/5 bg-black/40 backdrop-blur-3xl z-50 flex-shrink-0">
        <div className="w-full px-8 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-gradient-to-tr from-amber-500 to-yellow-200 rounded-full flex items-center justify-center shadow-[0_0_20px_rgba(251,191,36,0.3)]">
              <Sparkles size={20} className="text-black" />
            </div>
            <div>
              <h1 className="font-fashion text-xl md:text-2xl font-bold tracking-tight">TUẤN DZ <span className="text-[9px] font-sans bg-white text-black px-1.5 py-0.5 ml-1 rounded font-black">AI STUDIO</span></h1>
              <p className="text-[8px] uppercase tracking-[0.4em] text-white/30 font-bold">Fashion Ad Design specialist</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <button 
               onClick={() => setState(prev => ({ ...prev, showAIDashboard: !prev.showAIDashboard }))}
               className={`flex items-center gap-2 px-4 py-2 rounded-full text-[9px] font-black uppercase tracking-widest transition-all border ${state.showAIDashboard ? 'bg-amber-500 text-black border-amber-500' : 'bg-white/5 text-white/40 border-white/10 hover:text-white'}`}
             >
               {state.showAIDashboard ? <XCircle size={14} /> : <Sparkle size={14} />}
               {state.showAIDashboard ? 'Ẩn AI Tool' : 'Hiện AI Tool'}
             </button>

             <div className="px-4 py-2 bg-white/5 rounded-full border border-white/10 flex items-center gap-3">
               <Package size={14} className="text-amber-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">{state.items.length} SẢN PHẨM</span>
             </div>

             <button 
               onClick={handleExportAll}
               disabled={!state.image || isExporting}
               className={`bg-white text-black px-6 py-3 rounded-full font-black text-[10px] tracking-[0.2em] transition-all shadow-xl active:scale-95 flex items-center gap-2 ${(!state.image || isExporting) ? 'opacity-50 cursor-not-allowed' : 'hover:bg-red-600 hover:text-white'}`}
             >
                <Download size={14} /> XUẤT TOÀN BỘ
             </button>
          </div>
        </div>
      </header>

      <main className="flex-grow w-full flex overflow-hidden">
        <div className="flex-grow bg-[#14151a] relative flex flex-col items-center overflow-y-auto custom-scrollbar pt-8 pb-12 px-12">
          {!state.image && !isGenerating ? (
            <div className="w-full flex-grow flex items-center justify-center">
              <div className="w-full max-w-2xl aspect-square rounded-[50px] border-2 border-dashed border-white/10 bg-white/5 flex flex-col items-center justify-center gap-10 group cursor-pointer relative overflow-hidden transition-all hover:bg-white/[0.07] hover:border-red-500/50">
                 <input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer z-10" onChange={handleImageUpload} />
                 <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center text-white/10 group-hover:scale-110 group-hover:text-red-500 transition-all border border-white/5 shadow-inner">
                   <Files size={40} />
                 </div>
                 <div className="text-center z-10 space-y-3 px-10">
                   <p className="text-2xl font-fashion italic">Tải Hàng Loạt Ảnh</p>
                   <p className="text-[10px] text-white/20 uppercase tracking-[0.3em] font-bold">AI sẽ giữ nguyên mẫu và tạo bối cảnh sang trọng hơn</p>
                 </div>
              </div>
            </div>
          ) : (
            <div className="w-full max-w-4xl flex flex-col items-center gap-8 animate-in fade-in zoom-in-95 duration-1000">
              <div className="w-full flex overflow-x-auto gap-3 py-2 px-1 custom-scrollbar justify-center">
                {state.items.map((item, idx) => (
                  <button 
                    key={item.id}
                    onClick={() => setState(prev => ({ ...prev, selectedItemId: item.id }))}
                    className={`flex-shrink-0 w-16 h-16 rounded-lg border-2 transition-all relative overflow-hidden group ${state.selectedItemId === item.id ? 'border-red-500 bg-red-500/10 shadow-lg' : 'border-white/5 bg-white/5 hover:border-white/20'}`}
                  >
                    {item.image ? (
                      <img src={item.image} alt="" className="absolute inset-0 w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" />
                    ) : (
                      <ImageIcon className="text-white/10" size={14} />
                    )}
                  </button>
                ))}
                <div className="relative flex-shrink-0 w-16 h-16 rounded-lg border-2 border-dashed border-white/10 hover:border-white/40 flex items-center justify-center text-white/20 hover:text-white transition-all cursor-pointer">
                  <input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer z-10" onChange={handleImageUpload} />
                  <Plus size={14} />
                </div>
              </div>

              <div className="relative w-full max-w-xl group">
                {(isGenerating || state.isAnalyzing) && (
                  <div className="absolute inset-0 z-[60] bg-black/90 backdrop-blur-2xl flex flex-col items-center justify-center rounded-[40px]">
                    <Loader2 size={40} className="text-red-500 animate-spin mb-4" />
                    <p className="text-red-500 font-fashion italic text-xl">
                      {state.isAnalyzing ? "Đang giải mã phong cách..." : "AI đang vẽ bối cảnh..."}
                    </p>
                  </div>
                )}

                {/* Overlay nút So sánh & Quay lại */}
                {selectedItem?.originalImage && selectedItem.originalImage !== selectedItem.image && (
                  <div className="absolute top-4 right-4 z-50 flex gap-2">
                    <button 
                      onMouseDown={() => setIsComparing(true)}
                      onMouseUp={() => setIsComparing(false)}
                      onMouseLeave={() => setIsComparing(false)}
                      className="bg-black/60 backdrop-blur-md text-white px-4 py-2 rounded-full border border-white/20 text-[9px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-white hover:text-black transition-all"
                    >
                      <Eye size={12} /> {isComparing ? 'Đang hiện Gốc' : 'Giữ để So Sánh'}
                    </button>
                    <button 
                      onClick={handleRevert}
                      className="bg-red-500 text-white px-4 py-2 rounded-full border border-red-600 text-[9px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-white hover:text-red-500 transition-all shadow-lg"
                    >
                      <RotateCcw size={12} /> Quay lại gốc
                    </button>
                  </div>
                )}

                <PreviewCanvas 
                  image={displayImage} 
                  config={state.config}
                  item={selectedItem}
                  onUpdateOverlay={(updates) => updateConfig(updates)}
                />

                {isComparing && (
                  <div className="absolute inset-0 z-40 bg-black/20 pointer-events-none flex items-center justify-center">
                    <span className="bg-black/80 px-4 py-2 rounded-lg text-xs font-bold border border-white/20">XEM ẢNH GỐC</span>
                  </div>
                )}
              </div>

              {state.showAIDashboard && state.analysis && (
                <div className="w-full max-w-3xl mt-12 animate-in slide-in-from-bottom-4">
                  <AnalysisDisplay analysis={state.analysis} />
                </div>
              )}
            </div>
          )}
        </div>

        <div className="w-[450px] flex-shrink-0 bg-[#0a0b0d] border-l border-white/5 overflow-y-auto custom-scrollbar p-6 space-y-6">

          {/* Section: Nội dung Sale */}
          <section className="bg-white/5 p-6 rounded-[32px] border border-amber-500/20 space-y-5">
            <div className="flex items-center gap-3 border-b border-white/5 pb-3">
              <AlignCenter size={18} className="text-amber-500" />
              <h2 className="font-bold uppercase tracking-[0.2em] text-[10px] text-amber-500">Nội dung Sale</h2>
            </div>

            <div className="space-y-4">
               <div className="space-y-2">
                  <label className="text-[8px] font-black text-white/20 uppercase tracking-widest">Subtitle</label>
                  <input type="text" value={state.config.promotionSubtitle} onChange={(e) => updateConfig({ promotionSubtitle: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-xl px-4 py-3 text-xs outline-none focus:border-amber-500/50" />
                  <input type="range" min="0.3" max="2.5" step="0.1" value={state.config.headlineScale} onChange={(e) => updateConfig({ headlineScale: parseFloat(e.target.value) })} className="w-full accent-amber-500 h-1" />
               </div>
               <div className="space-y-2">
                  <label className="text-[8px] font-black text-white/20 uppercase tracking-widest">Headline chính</label>
                  <input type="text" value={state.config.promotionText} onChange={(e) => updateConfig({ promotionText: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-xl px-4 py-3 text-sm font-fashion font-bold italic outline-none focus:border-amber-500/50" />
                  <input type="range" min="0.5" max="3.5" step="0.1" value={state.config.promoTextScale} onChange={(e) => updateConfig({ promoTextScale: parseFloat(e.target.value) })} className="w-full accent-amber-500 h-1" />
               </div>
               <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-white/20 uppercase">Tiền tố giá</label>
                    <input type="text" value={state.config.pricePrefix} onChange={(e) => updateConfig({ pricePrefix: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-xl px-3 py-2 text-[10px] outline-none focus:border-amber-500/50" />
                    <input type="range" min="0.3" max="2.5" step="0.1" value={state.config.pricePrefixScale} onChange={(e) => updateConfig({ pricePrefixScale: parseFloat(e.target.value) })} className="w-full accent-amber-500 h-1" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-white/20 uppercase">Ghi chú chân</label>
                    <input type="text" value={state.config.bottomNote} onChange={(e) => updateConfig({ bottomNote: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-xl px-3 py-2 text-[10px] outline-none focus:border-amber-500/50" />
                    <input type="range" min="0.3" max="2.5" step="0.1" value={state.config.bottomNoteScale} onChange={(e) => updateConfig({ bottomNoteScale: parseFloat(e.target.value) })} className="w-full accent-amber-500 h-1" />
                  </div>
               </div>
            </div>
          </section>

          {/* Section: AI Dashboard (Conditional) */}
          {state.showAIDashboard && (
            <section className="bg-red-500/5 p-6 rounded-[32px] border border-red-500/20 space-y-5 animate-in slide-in-from-right-4">
              <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <Sparkles size={18} className="text-red-500" />
                    <h2 className="font-bold uppercase tracking-[0.2em] text-[10px] text-red-500">AI Redesign bối cảnh</h2>
                  </div>
                  {displayImage && (
                    <button onClick={handleBackgroundRedesign} className="flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest hover:bg-white hover:text-red-600 transition-all shadow-lg">
                      <Wand2 size={12} /> Bắt đầu vẽ
                    </button>
                  )}
              </div>

              {state.analysis && (
                <div className="grid grid-cols-1 gap-2 max-h-48 overflow-y-auto custom-scrollbar">
                  {state.analysis.suggestedThemes.map((theme, i) => (
                    <button key={i} onClick={() => applyTheme(theme.prompt)} className={`text-left p-3 rounded-2xl border transition-all ${backgroundPrompt === theme.prompt ? 'bg-red-600 border-red-600 text-white' : 'bg-black/40 border-white/5 text-white hover:border-red-500/50'}`}>
                      <p className="text-[10px] font-black uppercase tracking-widest mb-1">{theme.name}</p>
                      <p className={`text-[8px] opacity-60 italic`}>{theme.description}</p>
                    </button>
                  ))}
                </div>
              )}
              <textarea value={backgroundPrompt} onChange={(e) => setBackgroundPrompt(e.target.value)} placeholder="Mô tả bối cảnh..." className="w-full bg-black/40 border border-white/10 rounded-2xl p-4 text-xs focus:border-red-500 outline-none transition-all min-h-[80px]" />
            </section>
          )}

          {/* Section: Cấu hình giá */}
          <section className="bg-white/5 p-6 rounded-[32px] border border-white/10 space-y-5">
            <div className="flex items-center gap-3 border-b border-white/5 pb-3">
              <Tag size={18} className="text-white/40" />
              <h2 className="font-bold uppercase tracking-[0.2em] text-[10px]">Cấu hình giá</h2>
            </div>
            <div className="grid grid-cols-2 gap-3">
               <div className="space-y-1">
                  <label className="text-[8px] font-black text-white/20 uppercase">Giá gốc</label>
                  <input type="text" value={selectedItem.originalPrice} onChange={(e) => updateItem(state.selectedItemId, { originalPrice: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-lg px-3 py-2 text-xs outline-none" />
               </div>
               <div className="space-y-1">
                  <label className="text-[8px] font-black text-red-500 uppercase">Giá Sale</label>
                  <input type="text" value={selectedItem.salePrice} onChange={(e) => updateItem(state.selectedItemId, { salePrice: e.target.value })} className="w-full bg-red-600/10 border border-red-500/20 rounded-lg px-3 py-2 text-xs text-red-500 font-bold outline-none" />
               </div>
            </div>
            <div className="flex items-center justify-between">
                <span className="text-[9px] text-white/40 uppercase font-black">Nền khối giá</span>
                <button onClick={() => updateConfig({ showPriceBackground: !state.config.showPriceBackground })} className={`transition-all ${state.config.showPriceBackground ? 'text-amber-500' : 'text-white/10'}`}>
                  {state.config.showPriceBackground ? <ToggleRight size={32} /> : <ToggleLeft size={32} />}
                </button>
            </div>
            <div className="flex items-center gap-3">
                <span className="text-[8px] text-white/20 uppercase font-bold">Size Giá:</span>
                <input type="range" min="0.5" max="2.5" step="0.1" value={state.config.priceScale} onChange={(e) => updateConfig({ priceScale: parseFloat(e.target.value) })} className="w-full accent-amber-500 h-1" />
            </div>
          </section>

          {/* Section: Khung hình */}
          <section className="bg-white/5 p-6 rounded-[32px] border border-white/10 space-y-4">
            <div className="flex items-center gap-3 border-b border-white/5 pb-3">
              <Layout size={18} className="text-white/40" />
              <h2 className="font-bold uppercase tracking-[0.2em] text-[10px]">Khung hình</h2>
            </div>
            <div className="grid grid-cols-5 gap-2">
              {(['1:1', '3:4', '4:3', '9:16', '16:9'] as const).map(ratio => (
                <button key={ratio} onClick={() => updateConfig({ aspectRatio: ratio })} className={`py-3 rounded-xl text-[9px] font-black transition-all border ${state.config.aspectRatio === ratio ? 'bg-red-600 text-white border-red-600' : 'bg-transparent text-white/20 border-white/5'}`}>
                  {ratio}
                </button>
              ))}
            </div>
          </section>

          {/* Branding */}
          <section className="bg-white/5 p-6 rounded-[32px] border border-white/10 space-y-5">
            <div className="flex items-center gap-3 border-b border-white/5 pb-3">
              <Store size={18} className="text-white/40" />
              <h2 className="font-bold uppercase tracking-[0.2em] text-[10px]">Thương hiệu</h2>
            </div>
            <div className="grid grid-cols-2 gap-4">
               <div className="space-y-3">
                  <div className="relative h-16 bg-black/40 border border-white/10 rounded-2xl flex items-center justify-center group cursor-pointer overflow-hidden">
                    <input type="file" className="absolute inset-0 opacity-0 cursor-pointer z-10" onChange={handleLogoUpload} />
                    {state.config.logo ? <img src={state.config.logo} className={`h-8 object-contain ${state.config.logoColor === 'white' ? 'invert opacity-80' : ''}`} /> : <ImageIcon className="text-white/10" />}
                  </div>
                  <div className="flex gap-1">
                    <button onClick={() => updateConfig({ logoColor: 'white' })} className={`flex-1 py-1.5 rounded-lg text-[8px] font-black uppercase border ${state.config.logoColor === 'white' ? 'bg-white text-black' : 'text-white/20 border-white/5'}`}>Trắng</button>
                    <button onClick={() => updateConfig({ logoColor: 'black' })} className={`flex-1 py-1.5 rounded-lg text-[8px] font-black uppercase border ${state.config.logoColor === 'black' ? 'bg-black text-white' : 'text-white/20 border-white/5'}`}>Đen</button>
                  </div>
               </div>
               <div className="space-y-3">
                  <input type="text" value={state.config.brandName} onChange={(e) => updateConfig({ brandName: e.target.value })} className="w-full bg-black/40 border border-white/10 rounded-2xl px-4 py-3 h-16 text-xs font-fashion font-bold uppercase tracking-widest outline-none" placeholder="SHOP NAME" />
                  <input type="range" min="0.5" max="2.5" step="0.1" value={state.config.brandNameScale} onChange={(e) => updateConfig({ brandNameScale: parseFloat(e.target.value) })} className="w-full accent-red-600 h-1" />
               </div>
            </div>
          </section>

        </div>
      </main>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; height: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.1); }
      `}</style>
    </div>
  );
};

export default App;
